/* ============================================
   COMPREHENSIVE SESSION CONTENT — Sessions 1–6
   Every concept from every PDF slide included
   ============================================ */
const sessionContent = {
session1: {
    hero: { title:'Session 1: Introduction to Cyber Security in Manufacturing', desc:'Understand why manufacturing is the most targeted industry, learn the CIA Triad, explore IT vs OT, Cyber-Physical Systems, attack surfaces, real-world attacks, OT-specific challenges, and business & safety impacts.' },
    concepts: [
        { title:'🏭 Automation in Industry', body:`<p><strong>Industrial Automation</strong> uses control systems and technologies to automate industrial operations like manufacturing and assembly. Focus: discrete manufacturing (individual units like cars, gadgets). Tools: PLCs, SCADA, Robotics.</p><p><strong>Process Automation</strong> uses technology to control and monitor continuous processes without constant human intervention. Focus: continuous processes (fluids, gases, pressure, temperature). Tools: DCS, PLCs, SCADA.</p><table class="info-table"><tr><th>Aspect</th><th>Industrial Automation</th><th>Process Automation</th></tr><tr><td>Primary Focus</td><td>Discrete manufacturing — machines, robots, conveyors</td><td>Continuous processes — pressure, temperature, flow</td></tr><tr><td>Industries</td><td>Automotive, electronics, packaging, textile</td><td>Oil & gas, chemicals, pharmaceuticals, food processing</td></tr><tr><td>Control Systems</td><td>PLCs, SCADA, Robotics</td><td>DCS, PLCs, SCADA</td></tr><tr><td>Operation Type</td><td>Discrete (individual units)</td><td>Continuous (fluids, gases, mixtures)</td></tr><tr><td>Data Usage</td><td>Monitoring equipment and machinery</td><td>Extensive sensor feedback loops</td></tr><tr><td>Human Involvement</td><td>Reduced, operator oversees</td><td>More significant due to safety-critical nature</td></tr></table><p><strong>Automation Hierarchy (Purdue Model Preview):</strong> Level 0: Physical Process → Level 1: Control (PLCs) → Level 2: Supervisory (SCADA/HMI) → Level 3: Management (MES) → Level 4: Enterprise (ERP)</p>` },
        { title:'🔐 Why Cybersecurity in Manufacturing?', body:`<p><strong>Manufacturing is the #1 most targeted industry</strong> for cyberattacks (ransomware, espionage). Modern factories have high reliance on automation and connected systems (ICS, IoT, SCADA).</p><p><strong>Why manufacturers are prime targets:</strong></p><ul><li>Critical role in supply chains — disruption cascades globally</li><li>Valuable intellectual property (designs, formulas, processes)</li><li>Often outdated or poorly secured legacy systems</li><li>IT-OT convergence creates new attack vectors</li></ul><table class="info-table"><tr><th>Impact Category</th><th>Example</th><th>Cost/Consequence</th></tr><tr><td>Production Halts</td><td>Norsk Hydro (2019) — LockerGoga ransomware</td><td>$60-70M, weeks of manual operations</td></tr><tr><td>Safety Risks</td><td>German Steel Mill (2014) — blast furnace couldn't shut down</td><td>Physical damage, safety hazards</td></tr><tr><td>Financial Loss</td><td>Merck & Co. (2017) — NotPetya malware</td><td>$1.3 billion in damages</td></tr><tr><td>IP Theft</td><td>APT10 / Operation Cloud Hopper — Chinese hackers</td><td>Stolen blueprints, R&D data, designs</td></tr><tr><td>Downtime</td><td>Honda (2020) — targeted attack causing downtime</td><td>Production and communications halted</td></tr></table>` },
        { title:'🔐 The CIA Triad', body:`<p>The three pillars of information security. Every security control — firewalls, authentication, antivirus, monitoring — is ultimately designed to protect C, I, or A.</p><table class="info-table"><tr><th>Principle</th><th>Focus</th><th>Real-World Threat</th><th>Protection Methods</th></tr><tr><td><strong>Confidentiality</strong></td><td>Prevent unauthorized access to data</td><td>Data leaks, espionage, IP theft</td><td>Encryption, access control, MFA, RBAC</td></tr><tr><td><strong>Integrity</strong></td><td>Ensure data is unchanged and accurate</td><td>Data tampering, fraud, PLC logic modification</td><td>Hashing, digital signatures, logging, version control</td></tr><tr><td><strong>Availability</strong></td><td>Ensure access when needed, production continuity</td><td>Downtime, ransomware, DDoS attacks, hardware failure</td><td>Backups, redundancy, failover systems, UPS</td></tr></table><h5>CIA in Manufacturing Context</h5><table class="info-table"><tr><th>CIA Element</th><th>Manufacturing Example</th><th>Impact if Violated</th></tr><tr><td>Confidentiality</td><td>Protecting product formulas, CAD designs, CNC instructions</td><td>Trade secret leak, competitive loss</td></tr><tr><td>Integrity</td><td>Ensuring PLC code and temperature setpoints are unchanged</td><td>Defective parts, unsafe output (Stuxnet-like)</td></tr><tr><td>Availability</td><td>Keeping SCADA, HMI, production lines operational 24/7</td><td>Production stops (Colonial Pipeline-like)</td></tr></table><h5>Which CIA element is hardest to detect when violated?</h5><table class="info-table"><tr><th>CIA Element</th><th>Most Likely Unnoticed?</th><th>Most Dangerous in Safety-Critical OT?</th></tr><tr><td>Confidentiality</td><td>❌ Usually detected by DLP/alerts</td><td>⚠️ Important but less critical than A</td></tr><tr><td>Integrity</td><td>✅ Yes — hidden changes in logic go unnoticed</td><td>⚠️ Yes — causes silent failures</td></tr><tr><td>Availability</td><td>❌ Outages are obvious</td><td>✅ Yes — can result in unsafe shutdowns</td></tr></table><p><em>"Just because it looks like it's working, doesn't mean it's working right."</em> — Integrity attacks are the stealthiest.</p>` },
        { title:'💻 IT vs OT — The Critical Difference', body:`<table class="info-table"><tr><th>Aspect</th><th>IT (Information Technology)</th><th>OT (Operational Technology)</th></tr><tr><td>Main Purpose</td><td>Data management, digital solutions, business systems</td><td>Direct control of physical devices and processes</td></tr><tr><td>Environment</td><td>Offices, data centres</td><td>Factories, power plants, transportation</td></tr><tr><td>Examples</td><td>Email, ERP, CRM, cloud services, office software</td><td>PLCs, SCADA, HMI, CNC machines, robotics, sensors</td></tr><tr><td>Devices</td><td>Windows servers, PCs, mobile (3-5 year refresh)</td><td>Customized OS, embedded systems, PLCs (10-20+ year lifecycle)</td></tr><tr><td>Uptime & Redundancy</td><td>Common failover; rebooting has minimal impact</td><td>Minimal redundancy; rebooting disrupts critical processes</td></tr><tr><td>Infrastructure</td><td>Cloud-based or hybrid solutions</td><td>On-premises, slowly moving to cloud</td></tr><tr><td>Remediation</td><td>Simple (reboot, patch), low operational risk</td><td>Complex, high risk — wrong action can halt production</td></tr><tr><td>Threat Identification</td><td>Extensive public vulnerability DBs, lower zero-day exposure</td><td>Domain-specific threats, higher zero-day exposure (embedded devices)</td></tr><tr><td>Security Model</td><td>Frequent patching, antivirus, user access control</td><td>Often unpatched, strict reliability, minimal downtime tolerance</td></tr><tr><td>Priorities</td><td>Confidentiality and Integrity</td><td>Availability, Safety, real-time control</td></tr><tr><td>Compliance</td><td>Strict cybersecurity regulations</td><td>Early adoption, except energy sector (NERC CIP)</td></tr><tr><td>Users</td><td>Office workers, IT admins, executives</td><td>Engineers, technicians, control room operators</td></tr></table><p><strong>Car Manufacturing Example:</strong> IT tracks customer orders, handles billing, stores employee records. OT runs the robotic arms, conveyor belts, and temperature sensors on the assembly line. Both are critical but have very different roles, risks, and priorities.</p>` },
        { title:'🔓 Common Cyber Threats in Manufacturing', body:`<table class="info-table"><tr><th>Threat Type</th><th>Description</th><th>Impact</th><th>Example</th></tr><tr><td><strong>Ransomware</strong></td><td>Encrypts files, demands payment</td><td>Halts production, financial losses</td><td>WannaCry, LockerGoga</td></tr><tr><td><strong>Phishing & Social Engineering</strong></td><td>Tricks employees into revealing credentials</td><td>Credential theft, malware infections</td><td>Fake IT support emails</td></tr><tr><td><strong>Supply Chain Attacks</strong></td><td>Compromises third-party vendors/software</td><td>Backdoors into secure environments</td><td>SolarWinds attack</td></tr><tr><td><strong>Insider Threats</strong></td><td>Malicious or negligent employee actions</td><td>Sabotage, IP theft, unauthorized access</td><td>Disgruntled worker leaking data</td></tr><tr><td><strong>Unpatched Legacy Systems</strong></td><td>Outdated software with known vulnerabilities</td><td>Easy exploitation</td><td>Unsupported Windows XP systems</td></tr><tr><td><strong>Remote Access Exploits</strong></td><td>Insecure VPNs or RDP abused</td><td>Remote control without physical access</td><td>Brute-force attacks on RDP</td></tr><tr><td><strong>Denial of Service (DoS/DDoS)</strong></td><td>Systems overwhelmed with traffic</td><td>Production delays, system crashes</td><td>Botnet-based DoS attacks</td></tr><tr><td><strong>Data Theft / Espionage</strong></td><td>Stealing confidential manufacturing data</td><td>Competitive disadvantage, loss of IP</td><td>Theft of designs or formulas</td></tr></table>` },
        { title:'⚡ Cyber-Physical Systems (CPS)', body:`<p>CPS integrates <strong>computation, networking, and physical processes</strong> with feedback loops where embedded computers and networks monitor and control physical processes.</p><p><strong>Key Characteristics:</strong></p><ul><li><strong>Sensors</strong> gather data from physical machinery</li><li><strong>Controllers/PLCs</strong> make decisions based on real-time input</li><li><strong>Networks</strong> connect machines, control systems, and cloud platforms</li><li><strong>Actuators</strong> respond to system decisions (opening valves, stopping motors)</li></ul><p><strong>Examples in Industry:</strong> Automated robotic assembly lines, smart energy management systems, remote-controlled SCADA infrastructure, predictive maintenance using IIoT + AI</p><p>CPS is at the core of <strong>Industry 4.0 and 5.0</strong>, making cybersecurity essential for both operational continuity and human safety.</p>` },
        { title:'🎯 Attack Surface, Threat Vectors & Attack Vectors', body:`<table class="info-table"><tr><th>Term</th><th>What It Describes</th><th>Simple Analogy</th><th>Examples</th></tr><tr><td><strong>Threat Vector</strong></td><td>A <em>potential path</em> for threats to enter</td><td>A window that <em>could</em> be opened</td><td>USB ports, VPN, email, IoT devices, vendor connections</td></tr><tr><td><strong>Attack Vector</strong></td><td>The <em>actual method</em> used to exploit a system</td><td>The thief climbing through the window</td><td>RDP brute-force, phishing link, exploiting unpatched PLC firmware</td></tr><tr><td><strong>Attack Surface</strong></td><td>The <em>total area</em> exposed to threats</td><td>Every window, door, and gate of the castle</td><td>All connected PLCs, HMIs, open ports, employees, old software</td></tr></table><p><em>Reducing attack surface:</em> Zero Trust, network segmentation, patch management, disable unused ports/services, manage vendor access.</p><h5>Attack Surface Components in Manufacturing</h5><table class="info-table"><tr><th>Attack Surface</th><th>Example Scenario</th><th>Risk Level</th></tr><tr><td>Legacy Systems</td><td>SCADA on Windows XP exploited by EternalBlue (WannaCry)</td><td>🔴 High</td></tr><tr><td>Insecure Remote Access</td><td>TeamViewer with no MFA used to control HMI (Oldsmar)</td><td>🔴 High</td></tr><tr><td>Third-Party Vendors</td><td>Infected vendor laptop spreads malware to OT network</td><td>🟡 Medium-High</td></tr><tr><td>Misconfigured IIoT</td><td>Sensor with admin/admin credentials hijacked for crypto mining</td><td>🟡 Medium</td></tr><tr><td>Insider Threats</td><td>Former employee uses old VPN credentials to delete PLC configs</td><td>🔴 High</td></tr></table>` },
        { title:'🔓 OT Vulnerabilities — Deep Dive', body:`<h5>1. Lack of Encryption/Authentication in Legacy Systems</h5><ul><li>Many OT systems were never designed with security in mind</li><li>No encryption or device authentication — commands sent in clear text</li><li>📍Risk: Attackers can intercept or inject control commands</li></ul><h5>2. Poor Patching Practices</h5><ul><li>Patching often delayed because uptime > security</li><li>Legacy systems may not support modern updates</li><li>📍Risk: Known vulnerabilities remain exploitable for months/years</li></ul><h5>3. Human Errors & Social Engineering</h5><ul><li>OT staff may lack cybersecurity training</li><li>Phishing, misconfigurations, USB misuse are common</li><li>📍Risk: Easy entry point for malware (e.g., Stuxnet via USB)</li></ul><h5>4. Default Passwords & Remote Access Misuse</h5><ul><li>Devices deployed with unchanged default credentials (admin/admin)</li><li>Insecure remote access tools (RDP, TeamViewer) with no MFA</li><li>📍Risk: Brute-force attacks or unauthorized remote access</li></ul><p><strong>Takeaway:</strong> OT security is not just about technology — it's also about people, processes, and proper integration with IT security policies.</p>` },
        { title:'⚠️ OT-Specific Challenges', body:`<table class="info-table"><tr><th>Challenge</th><th>Explanation</th><th>Example</th></tr><tr><td><strong>Availability Over Security</strong></td><td>OT systems built to run 24/7. Security was never the primary design focus.</td><td>Power grid control room keeps electricity flowing; shutting down for updates risks blackout — so security gets ignored.</td></tr><tr><td><strong>Low Latency Tolerance</strong></td><td>Real-time control systems can't tolerate delays. Even security tools (DPI, antivirus scans) cause disruption.</td><td>Automated bottling line: 100ms firewall delay causes conveyor misalignment or unexpected halt.</td></tr><tr><td><strong>Patching = Production Downtime</strong></td><td>Applying updates to PLCs/HMIs/industrial PCs means stopping production — lost output and revenue.</td><td>Steel plant running 24/7: HMI security patch requires 6 hours shutdown. Management delays patch — system stays vulnerable.</td></tr><tr><td><strong>Long Hardware Lifecycle (10-20+ years)</strong></td><td>Unlike IT (3-5 years), OT devices last decades. They don't support modern security protocols.</td><td>Legacy Siemens PLC from 2004 still in use. Can't support encrypted communication or MFA. Default Modbus ports exploitable.</td></tr></table>` },
        { title:'💰 Business & Safety Impacts — Full Detail', body:`<table class="info-table"><tr><th>Impact</th><th>Explanation</th><th>Example</th><th>Consequence</th></tr><tr><td><strong>Financial Losses</strong></td><td>Attack halts production, ransom payments, recovery costs</td><td>Colonial Pipeline (2021): $4.4M ransom + days of fuel delivery delays</td><td>Revenue loss, ransom, emergency recovery</td></tr><tr><td><strong>Supply Chain Disruption</strong></td><td>One site's attack ripples through suppliers/logistics/customers</td><td>Norsk Hydro (2019): global aluminum supply disrupted, automotive companies paused</td><td>JIT systems especially sensitive</td></tr><tr><td><strong>Equipment Damage</strong></td><td>Malware tampering with control logic causes machine malfunction</td><td>Stuxnet: ~1,000 centrifuges physically destroyed while reporting normal values</td><td>Costly repairs or replacements</td></tr><tr><td><strong>Safety Hazards</strong></td><td>Tampering with chemicals, motor speeds, environmental controls</td><td>Oldsmar (2021): sodium hydroxide increased from 100 to 11,100 ppm in drinking water</td><td>Human lives endangered</td></tr><tr><td><strong>Customer Trust & Reputation</strong></td><td>Breaches erode confidence, damage brand, regulatory fines</td><td>Target data breach (2013) via third-party HVAC vendor: millions of records exposed</td><td>Lawsuits, lost customers</td></tr></table>` },
        { title:'🔍 HMI Security Risk Assessment', body:`<p>HMIs (Human-Machine Interfaces) are operator dashboards that control industrial systems. Their security posture varies widely:</p><table class="info-table"><tr><th>Security Factor</th><th>⚠️ High Risk HMI</th><th>✅ Low Risk HMI</th></tr><tr><td>Login Protection</td><td>Default username/password (admin/admin)</td><td>Custom, strong password required</td></tr><tr><td>Access Control</td><td>No role separation; all users = same rights</td><td>Role-based access (operator vs engineer)</td></tr><tr><td>Network Exposure</td><td>Directly accessible on internal/public network</td><td>Behind firewall or in DMZ</td></tr><tr><td>Logging / Audit Trail</td><td>No log of actions or changes</td><td>Alarm, history, and login tracking enabled</td></tr><tr><td>Software Updates</td><td>Running outdated/unsupported versions</td><td>Up-to-date with vendor patches</td></tr><tr><td>Protocol Hardening</td><td>Unsecured protocols (open Modbus TCP)</td><td>Encrypted or authenticated channels</td></tr><tr><td>Physical Access</td><td>HMI exposed in public/visitor areas</td><td>Located in restricted/monitored zones</td></tr></table>` }
    ],
    caseStudies: [
        { name:'Stuxnet (2010)', detail:'Nation-state cyberweapon targeting Siemens PLCs in Iran\'s Natanz nuclear facility. Spread via USB → infected Windows IT systems → reached and manipulated PLCs in centrifuge control. Intercepted and modified PLC commands, causing centrifuges to spin at damaging speeds while reporting normal behavior to operators on HMI. Used 4 zero-day exploits.', impact:'~1,000 centrifuges destroyed, delayed nuclear enrichment, first known cyber-physical weapon', lesson:'OT systems, even air-gapped ones, can be compromised via USB/vendor laptops. IT-OT bridges can be exploited. Integrity of operations is a critical risk. Detection would have been possible with motor speed logging, anomaly detection, and PLC change monitoring.' },
        { name:'Norsk Hydro / LockerGoga (2019)', detail:'LockerGoga ransomware breached IT systems of global aluminum manufacturer. OT systems were NOT directly targeted, but IT breach severely impacted plant operations. Plants couldn\'t receive production orders, control machines, or access files. Employees used pen and paper for critical tasks. Company had flat internal networks → ransomware spread quickly. Backup systems were also affected.', impact:'$60-70M damages, production shutdowns across multiple plants globally, manual operations for days/weeks, supply chain disruptions', lesson:'IT-OT dependency means IT breach = OT disruption. Need network segmentation (DMZ, firewalls, VLANs), ransomware-specific recovery plans, and tested backup procedures. Primary CIA violation: Availability.' },
        { name:'Colonial Pipeline (2021)', detail:'DarkSide ransomware breached IT billing/business network via compromised VPN credentials (no MFA). OT pipeline operations were NOT directly hit but were voluntarily shut down due to fear of lateral movement to OT and inability to run billing without IT.', impact:'Fuel shortages across US East Coast, panic buying, price spikes, $4.4M ransom paid, government emergency declaration', lesson:'IT breach can trigger voluntary OT shutdown. Need: MFA on all remote access, IT-OT network segmentation, incident response plans, backup strategy. All three CIA elements violated.' },
        { name:'Oldsmar Water Plant (2021)', detail:'Attacker used TeamViewer (left exposed with no MFA) to remotely access operator HMI. Increased sodium hydroxide (lye) from 100 ppm to 11,100 ppm — a dangerously toxic level. A human operator saw the cursor moving and reversed the change in real-time. No exploits needed — just poor cyber hygiene.', impact:'Near-poisoning of public water supply, FBI investigation, public panic, global awareness of HMI vulnerabilities', lesson:'Basic hygiene failures (no MFA, exposed remote access) can threaten public safety. First widely known case where simple remote-access exposure nearly caused chemical manipulation of infrastructure. Primary CIA violation: Integrity.' },
        { name:'TRITON / TRISIS (2017)', detail:'Targeted a Safety Instrumented System (SIS) in a Middle Eastern petrochemical plant. Gained access via a vulnerable engineering workstation, then attempted to reprogram the SIS controller. Goal was to disable safety systems that prevent catastrophic equipment failure.', impact:'Could have led to physical equipment damage or loss of life. First known malware to directly target safety systems.', lesson:'Even safety-critical systems can be compromised. Need: network segmentation for SIS, MFA on engineering workstations, code auditing for safety controllers.' },
        { name:'BlackEnergy (Ukraine 2015)', detail:'Used spear-phishing emails to gain initial access to IT systems, then moved laterally through IT and into SCADA systems controlling Ukraine\'s power grid. Caused a major power blackout affecting 230,000 customers.', impact:'First confirmed cyberattack to take down a power grid, 230,000 customers without power for hours.', lesson:'Phishing can be the entry point for critical infrastructure attacks. Need: email security, IT-OT segmentation, SCADA monitoring, incident response planning.' }
    ],
    flashcards: [
        { front:'CIA Triad', back:'Confidentiality, Integrity, Availability — the three pillars of information security. Every security control ultimately protects one or more of these.' },
        { front:'OT vs IT: Key Priority Difference', back:'OT prioritizes Availability & Safety (production must not stop). IT prioritizes Confidentiality & Integrity (data must be protected).' },
        { front:'OT System Lifespan', back:'10-20+ years, compared to IT\'s 3-5 year refresh cycle. This means OT devices often can\'t support modern security features like encryption or MFA.' },
        { front:'Attack Surface', back:'The total area of a system exposed to threats — every device, port, protocol, person, and service that could be attacked. Reduced by Zero Trust, segmentation, patching.' },
        { front:'Threat Vector vs Attack Vector', back:'Threat Vector = potential path for threats (USB port exists). Attack Vector = actual method used (Stuxnet spread via infected USB).' },
        { front:'Stuxnet Significance', back:'First known malware to target ICS for physical sabotage (2010). Proved cyberattacks can cause kinetic damage. Targeted Siemens PLCs via USB, used 4 zero-days.' },
        { front:'Colonial Pipeline Key Failure', back:'Compromised VPN credentials with NO MFA. IT breach led to voluntary OT shutdown due to fear of lateral movement. $4.4M ransom paid.' },
        { front:'Oldsmar Water Attack Method', back:'Attacker used TeamViewer (no MFA) to access HMI and change sodium hydroxide from 100 to 11,100 ppm. Caught by alert operator. No exploits needed — just poor cyber hygiene.' },
        { front:'Integrity Attack in OT', back:'The hardest to detect — hidden changes in control logic (e.g., Stuxnet modified PLC code while showing normal readings on HMI). "Just because it looks like it\'s working, doesn\'t mean it\'s working right."' },
        { front:'TRITON / TRISIS (2017)', back:'First malware to target a Safety Instrumented System (SIS). Attempted to reprogram safety controllers in a petrochemical plant. Could have caused physical damage or death.' },
        { front:'BlackEnergy (2015)', back:'Spear-phishing → IT access → lateral movement → SCADA control → Ukraine power grid blackout affecting 230,000 customers. First confirmed grid-level cyberattack.' },
        { front:'Norsk Hydro Lesson', back:'Flat internal network allowed ransomware (LockerGoga) to spread rapidly. $60-70M damage. Lesson: need network segmentation, backup testing, and ransomware recovery plans.' },
        { front:'OT-Specific Challenge: Latency', back:'Real-time control systems can\'t tolerate delays. Even 100ms added by a firewall can cause conveyor misalignment or machine halt.' },
        { front:'OT-Specific Challenge: Patching', back:'Applying security patches to PLCs/HMIs requires production downtime. Management often delays patches, leaving systems vulnerable to known exploits.' },
        { front:'Industrial vs Process Automation', back:'Industrial = discrete manufacturing (cars, gadgets) using PLCs/Robotics. Process = continuous flows (chemicals, oil) using DCS/SCADA. Both need cybersecurity.' },
        { front:'Cyber-Physical Systems (CPS)', back:'Integration of computation, networking, and physical processes with feedback loops. Core of Industry 4.0/5.0. Sensors → Controllers → Actuators → Networks.' },
        { front:'Zero Day Vulnerability', back:'A vulnerability unknown to the vendor with no patch available. Highest risk in OT due to long lifecycles and rare patching.' },
        { front:'Merck NotPetya (2017)', back:'NotPetya malware caused $1.3 billion in damages. Halted production, disrupted global supply chains. Shows financial magnitude of cyber risk.' },
        { front:'APT10 / Operation Cloud Hopper', back:'Chinese state-sponsored hackers targeted aerospace and manufacturing firms worldwide to steal blueprints, R&D data, and engineering designs.' },
        { front:'German Steel Mill (2014)', back:'Cyberattack prevented blast furnace from shutting down properly, causing massive physical damage and safety hazards.' }
    ]
},
session2: {
    hero: { title:'Session 2: Networking Concepts & Commands', desc:'Master network types, OSI & TCP/IP models, IP addressing, subnetting, network devices, ports & protocols, topologies, network communication (ARP/DNS/DHCP), security tools (Wireshark), and common network attacks.' },
    concepts: [
        { title:'🌐 What is a Network & Network Types', body:`<p>A <strong>network</strong> is a group of interconnected devices (computers, servers, phones, printers) that can communicate and share resources.</p><table class="info-table"><tr><th>Type</th><th>Full Form</th><th>Coverage</th><th>Example</th></tr><tr><td><strong>PAN</strong></td><td>Personal Area Network</td><td>Few meters (room)</td><td>Bluetooth phone ↔ smartwatch</td></tr><tr><td><strong>LAN</strong></td><td>Local Area Network</td><td>Building/campus</td><td>Office computers + printers on one router</td></tr><tr><td><strong>MAN</strong></td><td>Metropolitan Area Network</td><td>City/metro region</td><td>University inter-campus connectivity</td></tr><tr><td><strong>WAN</strong></td><td>Wide Area Network</td><td>Countries/global</td><td>The Internet, corporate networks</td></tr></table><h5>Network Architectures</h5><table class="info-table"><tr><th>Type</th><th>Description</th><th>Example</th></tr><tr><td><strong>Client-Server</strong></td><td>Central server provides resources/services to clients</td><td>Google Drive (server) accessed by users (clients)</td></tr><tr><td><strong>Peer-to-Peer (P2P)</strong></td><td>All devices are equal, share resources directly</td><td>BitTorrent file sharing</td></tr></table>` },
        { title:'📡 OSI Model (7 Layers) — Complete', body:`<p><strong>Purpose:</strong> Standardize networking functions into layers. Security must be considered at EVERY layer.</p><table class="info-table"><tr><th>Layer</th><th>Name</th><th>Function</th><th>Unit</th><th>Protocols</th><th>Threats</th><th>Defenses</th></tr><tr><td>7</td><td>Application</td><td>User interface</td><td>Data</td><td>HTTP, HTTPS, FTP, SMTP, DNS, DHCP, SNMP, LDAP, Telnet</td><td>Malware, phishing, MitM, data leaks</td><td>TLS/SSL, MFA, input validation, antivirus</td></tr><tr><td>6</td><td>Presentation</td><td>Format/encrypt data</td><td>Data</td><td>SSL/TLS, JPEG, MIME, JSON, XML, ASCII</td><td>Data tampering, format exploits, downgrade attacks</td><td>Encryption, secure parsing, hashing</td></tr><tr><td>5</td><td>Session</td><td>Manage sessions</td><td>Data</td><td>NetBIOS, SIP, PPTP, L2TP</td><td>Session hijacking, replay attacks</td><td>Token auth, session keys, timeouts</td></tr><tr><td>4</td><td>Transport</td><td>Delivery control</td><td>Segments/Datagrams</td><td>TCP, UDP, TLS/SSL, SCTP</td><td>SYN flood, port scanning, UDP flooding</td><td>Stateful firewalls, rate limiting, SYN cookies</td></tr><tr><td>3</td><td>Network</td><td>Routing/IP</td><td>Packets</td><td>IPv4, IPv6, ICMP, OSPF, BGP, IPsec</td><td>IP spoofing, route hijacking, ICMP floods</td><td>ACLs, VPNs, IPsec, packet filtering</td></tr><tr><td>2</td><td>Data Link</td><td>MAC/Switching</td><td>Frames</td><td>ARP, Ethernet, PPP, Wi-Fi (802.11)</td><td>ARP spoofing, MAC spoofing</td><td>VLANs, MAC filtering, DAI, port security</td></tr><tr><td>1</td><td>Physical</td><td>Bit transmission</td><td>Bits (0s and 1s)</td><td>Cables, Wi-Fi RF, USB, RS-232, Bluetooth</td><td>Wiretapping, signal jamming, tampering</td><td>Shielded cables, physical security, locks</td></tr></table>` },
        { title:'🔄 TCP/IP Model (4 Layers)', body:`<p>The practical networking model used on the Internet. Maps to OSI model.</p><table class="info-table"><tr><th>TCP/IP Layer</th><th>Maps to OSI</th><th>Function</th><th>Protocols</th><th>Threats</th><th>Defenses</th></tr><tr><td>Application</td><td>Layers 5-7</td><td>User services</td><td>HTTP, FTP, DNS, SMTP, DHCP</td><td>Phishing, malware, DNS spoofing</td><td>Antivirus, DNSSEC, rate limiting</td></tr><tr><td>Transport</td><td>Layer 4</td><td>Reliable/fast delivery</td><td>TCP, UDP</td><td>SYN flood, port scanning</td><td>Firewalls, SYN cookies</td></tr><tr><td>Internet</td><td>Layer 3</td><td>Logical addressing & routing</td><td>IP, ICMP</td><td>IP spoofing, ICMP floods</td><td>VPNs, ACLs, IPsec</td></tr><tr><td>Network Access</td><td>Layers 1-2</td><td>Physical addressing & media</td><td>Ethernet, ARP, Wi-Fi</td><td>MAC spoofing, ARP poisoning</td><td>Port security, DAI, WPA2</td></tr></table>` },
        { title:'🔢 IP Addressing & Subnetting', body:`<h5>IPv4 Addressing</h5><p>32-bit address, written as 4 decimal numbers (0-255). Example: 192.168.1.1. Uniquely identifies a device on a network.</p><table class="info-table"><tr><th>Category</th><th>Private IP</th><th>Public IP</th></tr><tr><td>Definition</td><td>Used within local network (LAN)</td><td>Used on the internet</td></tr><tr><td>Routable?</td><td>❌ Not routable on internet</td><td>✅ Routable globally</td></tr><tr><td>Ranges</td><td>10.0.0.0-10.255.255.255, 172.16.0.0-172.31.255.255, 192.168.0.0-192.168.255.255</td><td>Everything outside private ranges</td></tr><tr><td>Assigned By</td><td>Router (DHCP/NAT)</td><td>ISP</td></tr></table><h5>IP Classes</h5><table class="info-table"><tr><th>Class</th><th>Range</th><th>Default Mask</th><th>Hosts/Network</th></tr><tr><td>A</td><td>1-126</td><td>/8 (255.0.0.0)</td><td>~16 million</td></tr><tr><td>B</td><td>128-191</td><td>/16 (255.255.0.0)</td><td>~65,000</td></tr><tr><td>C</td><td>192-223</td><td>/24 (255.255.255.0)</td><td>254</td></tr></table><h5>Subnetting & CIDR</h5><p><strong>Subnetting</strong> divides large networks into smaller, manageable sub-networks. <strong>CIDR</strong> (Classless Inter-Domain Routing) uses /n notation (e.g., /24 = 254 usable hosts). Benefits: isolates segments, reduces broadcast traffic, enhances security.</p><h5>NAT (Network Address Translation)</h5><p>Translates private IPs to a public IP. Types: Static NAT, Dynamic NAT, PAT (Port Address Translation). Benefits: conserves IPv4, hides internal structure, adds security.</p><h5>MAC Address</h5><p>48-bit hardware identifier (e.g., 00:1A:2B:3C:4D:5E). Used at Layer 2 for local device identification. First 3 bytes = OUI (manufacturer), last 3 bytes = NIC-specific. Permanent (burned-in) but can be spoofed.</p><table class="info-table"><tr><th>Feature</th><th>MAC Address</th><th>IP Address</th></tr><tr><td>Layer</td><td>Data Link (Layer 2)</td><td>Network (Layer 3)</td></tr><tr><td>Assigned by</td><td>Manufacturer</td><td>Network admin / ISP</td></tr><tr><td>Type</td><td>Physical address</td><td>Logical address</td></tr><tr><td>Scope</td><td>Local (same network)</td><td>Global (across networks)</td></tr></table>` },
        { title:'🔌 Network Devices — Complete', body:`<table class="info-table"><tr><th>Device</th><th>Function</th><th>Key Feature</th><th>Layer</th></tr><tr><td><strong>Hub</strong></td><td>Broadcasts data to ALL connected devices</td><td>No intelligence — dumb broadcast (legacy)</td><td>L1</td></tr><tr><td><strong>Switch</strong></td><td>Forwards data to SPECIFIC device using MAC addresses</td><td>Smart forwarder, creates separate collision domains</td><td>L2</td></tr><tr><td><strong>Router</strong></td><td>Connects different networks, routes traffic between them</td><td>Uses IP addresses, connects LAN to WAN/Internet</td><td>L3</td></tr><tr><td><strong>Firewall</strong></td><td>Monitors/controls network traffic based on security rules</td><td>Block unauthorized access, permit legitimate traffic</td><td>L3-L7</td></tr><tr><td><strong>Access Point</strong></td><td>Extends wired network with Wi-Fi capability</td><td>Wireless coverage expansion</td><td>L2</td></tr></table><h5>Firewall Types</h5><ul><li><strong>Packet-filtering</strong> — checks packet headers (IP, port)</li><li><strong>Stateful inspection</strong> — tracks connection states (TCP handshake)</li><li><strong>Application-level gateway</strong> — inspects application data (HTTP, DNS)</li><li><strong>Next-Gen (NGFW)</strong> — combines all above + DPI, threat intelligence</li></ul><h5>Industrial vs Standard Firewalls</h5><table class="info-table"><tr><th>Type</th><th>Where Used</th><th>Special Feature</th></tr><tr><td>Hardware Firewall</td><td>Homes, offices, data centers</td><td>Physical device, high performance</td></tr><tr><td>Industrial Firewall</td><td>Manufacturing, energy, automation</td><td>Industrial protocol support (Modbus, DNP3), rugged</td></tr><tr><td>Dedicated Firewall</td><td>Data centers, enterprises</td><td>Full control, flexible configuration</td></tr></table><h5>VLANs (Virtual LANs)</h5><p>Logically group devices even on different physical segments. Operate at Layer 2. Benefits: enhanced segmentation, improved security/performance, simplified management. Example: VLAN 10 = Marketing, VLAN 20 = Engineering.</p>` },
        { title:'📊 Ports & Protocols — Complete Reference', body:`<table class="info-table"><tr><th>Protocol</th><th>Port</th><th>TCP/UDP</th><th>Description</th></tr><tr><td>HTTP</td><td>80</td><td>TCP</td><td>Web traffic (unencrypted)</td></tr><tr><td>HTTPS</td><td>443</td><td>TCP</td><td>Secure web (TLS encrypted)</td></tr><tr><td>FTP Control</td><td>21</td><td>TCP</td><td>File Transfer Protocol (commands)</td></tr><tr><td>FTP Data</td><td>20</td><td>TCP</td><td>File Transfer Protocol (data)</td></tr><tr><td>SSH / SFTP</td><td>22</td><td>TCP</td><td>Secure remote login / secure file transfer</td></tr><tr><td>Telnet</td><td>23</td><td>TCP</td><td>Unsecure remote login (avoid!)</td></tr><tr><td>SMTP</td><td>25</td><td>TCP</td><td>Send email</td></tr><tr><td>DNS</td><td>53</td><td>UDP/TCP</td><td>Domain name resolution</td></tr><tr><td>DHCP</td><td>67/68</td><td>UDP</td><td>Dynamic IP assignment (server/client)</td></tr><tr><td>TFTP</td><td>69</td><td>UDP</td><td>Trivial FTP — basic file transfers</td></tr><tr><td>POP3</td><td>110</td><td>TCP</td><td>Receive email (download)</td></tr><tr><td>NTP</td><td>123</td><td>UDP</td><td>Network Time Protocol</td></tr><tr><td>IMAP</td><td>143</td><td>TCP</td><td>Receive email (sync)</td></tr><tr><td>SNMP</td><td>161</td><td>UDP</td><td>Network monitoring</td></tr><tr><td>LDAP</td><td>389</td><td>TCP/UDP</td><td>Directory access (Active Directory)</td></tr><tr><td>SMB</td><td>445</td><td>TCP</td><td>Windows file/printer sharing</td></tr><tr><td>Modbus</td><td>502</td><td>TCP</td><td>Industrial control protocol</td></tr><tr><td>Syslog</td><td>514</td><td>UDP</td><td>Logging for network devices</td></tr><tr><td>OpenVPN</td><td>1194</td><td>UDP</td><td>Secure VPN connections</td></tr><tr><td>MySQL</td><td>3306</td><td>TCP</td><td>MySQL database</td></tr><tr><td>RDP</td><td>3389</td><td>TCP</td><td>Remote Desktop Protocol</td></tr><tr><td>PostgreSQL</td><td>5432</td><td>TCP</td><td>PostgreSQL database</td></tr></table><h5>TCP vs UDP</h5><table class="info-table"><tr><th>Feature</th><th>TCP</th><th>UDP</th></tr><tr><td>Connection</td><td>Connection-oriented (3-way handshake: SYN → SYN-ACK → ACK)</td><td>Connectionless — no handshake</td></tr><tr><td>Reliability</td><td>Guaranteed delivery and order</td><td>No guarantee of delivery or order</td></tr><tr><td>Speed</td><td>Slower (overhead for reliability)</td><td>Faster (minimal overhead)</td></tr><tr><td>Use Cases</td><td>Web, email, file transfer</td><td>Streaming, DNS, gaming, VoIP</td></tr></table><h5>Well-Known vs Ephemeral Ports</h5><p><strong>Well-known (0-1023):</strong> Assigned by IANA for common protocols. <strong>Ephemeral (49152-65535):</strong> Temporary client-side ports assigned dynamically by the OS.</p>` },
        { title:'🔀 Network Topologies', body:`<table class="info-table"><tr><th>Topology</th><th>Structure</th><th>Pros</th><th>Cons</th></tr><tr><td><strong>Star</strong></td><td>All devices connect to central switch/hub</td><td>Easy to add devices, fault isolation</td><td>Central point of failure</td></tr><tr><td><strong>Bus</strong></td><td>All devices share one cable</td><td>Simple, cheap</td><td>Single cable failure = all down</td></tr><tr><td><strong>Ring</strong></td><td>Devices connect in a circular chain</td><td>Equal access, predictable</td><td>One device failure can break ring</td></tr><tr><td><strong>Mesh</strong></td><td>Every device connects to every other</td><td>Maximum redundancy & reliability</td><td>Expensive, complex wiring</td></tr></table><p><strong>Industrial Relevance:</strong> Star for modular, scalable setups. Mesh for resilience and real-time systems. Choice depends on latency, redundancy, scalability, and cost.</p>` },
        { title:'📨 Network Communication: ARP, DNS, DHCP', body:`<h5>ARP (Address Resolution Protocol)</h5><p>Resolves IP addresses to MAC addresses on a local network. Process: Device needs to send data → broadcasts ARP request ("Who has this IP?") → target responds with its MAC → device caches MAC and communicates directly.</p><h5>DNS (Domain Name System)</h5><p>Resolves domain names (google.com) to IP addresses. Two resolution types:</p><ul><li><strong>Recursive:</strong> DNS resolver does all the work, returns final answer to client</li><li><strong>Iterative:</strong> Client queries multiple DNS servers directly, gets referrals</li></ul><h5>DHCP (Dynamic Host Configuration Protocol)</h5><p>Automatically assigns IP addresses to devices joining a network. Uses the <strong>DORA</strong> process:</p><table class="info-table"><tr><th>Step</th><th>Direction</th><th>Type</th><th>Purpose</th></tr><tr><td><strong>D</strong>iscover</td><td>Client → Broadcast</td><td>Broadcast</td><td>Client doesn't know server's IP</td></tr><tr><td><strong>O</strong>ffer</td><td>Server → Client</td><td>Unicast/Broadcast</td><td>Server offers an IP address</td></tr><tr><td><strong>R</strong>equest</td><td>Client → Broadcast</td><td>Broadcast</td><td>Client tells all servers which offer accepted</td></tr><tr><td><strong>A</strong>cknowledge</td><td>Server → Client</td><td>Unicast</td><td>Server confirms IP lease</td></tr></table><p><strong>Key Points:</strong> Automatic (no manual config), Dynamic (IPs are leased temporarily), Centralized, Fallback to 169.254.x.x if no DHCP.</p>` },
        { title:'🛡️ Network Security: IDS, IPS, DMZ, Segmentation', body:`<h5>IDS vs IPS</h5><table class="info-table"><tr><th>Feature</th><th>IDS (Intrusion Detection)</th><th>IPS (Intrusion Prevention)</th></tr><tr><td>Action</td><td>Detect & Alert only</td><td>Detect & Block actively</td></tr><tr><td>Placement</td><td>Out-of-path (monitor mode)</td><td>In-path (inline)</td></tr><tr><td>Latency</td><td>No impact</td><td>May add slight latency</td></tr><tr><td>Examples</td><td>Snort</td><td>Suricata</td></tr></table><h5>DMZ (Demilitarized Zone)</h5><p>Buffer zone between untrusted external network (Internet) and trusted internal network (LAN). Hosts public-facing services while isolating internal resources.</p><table class="info-table"><tr><th>Source</th><th>Destination</th><th>Access?</th></tr><tr><td>Internet</td><td>Web Server (DMZ)</td><td>✅ Public access</td></tr><tr><td>Internet</td><td>Internal Computer</td><td>❌ Blocked by firewall</td></tr><tr><td>Internal</td><td>Internet</td><td>✅ Outbound allowed</td></tr><tr><td>DMZ Server</td><td>Internal LAN</td><td>❌ No direct access</td></tr></table><h5>Network Segmentation</h5><p>Dividing a network into smaller parts to control traffic, limit lateral movement, improve performance, and simplify monitoring.</p>` },
        { title:'🔧 Essential Network Tools', body:`<table class="info-table"><tr><th>Tool</th><th>What It Does</th><th>How It Works</th><th>Example</th></tr><tr><td><strong>ping</strong></td><td>Tests host reachability</td><td>Sends ICMP echo requests, measures response time</td><td>ping google.com</td></tr><tr><td><strong>traceroute/tracert</strong></td><td>Shows packet path to destination</td><td>Increments TTL to reveal each hop</td><td>tracert google.com (Windows)</td></tr><tr><td><strong>netstat</strong></td><td>Displays active connections & open ports</td><td>Shows services using the network</td><td>netstat -an</td></tr><tr><td><strong>ipconfig/ifconfig</strong></td><td>Shows IP configuration</td><td>Displays IP, subnet mask, gateway</td><td>ipconfig /all (Windows)</td></tr></table><h5>Wireshark — Packet Analyzer</h5><ul><li>Powerful graphical packet analyzer for real-time capture</li><li>Deep inspection of hundreds of protocols</li><li>Save captures for offline analysis</li><li>Visualize TCP streams and protocol hierarchies</li><li><strong>Exercise:</strong> Start Wireshark → select interface → filter: <code>http</code> or <code>ip.addr == target</code> → visit website → stop capture → inspect layers → Right-click > Follow > TCP Stream</li></ul>` },
        { title:'⚠️ Common Network Attacks — Complete', body:`<h5>Attack Categories</h5><table class="info-table"><tr><th>Category</th><th>Attack</th><th>Description</th><th>Attack Vector</th></tr><tr><td>🎣 Social Engineering</td><td>Phishing / Spear Phishing / Smishing / Vishing</td><td>Tricks users via fake emails, SMS, or phone calls</td><td>Email, SMS, Phone</td></tr><tr><td>🧮 Injection</td><td>SQL Injection, XSS</td><td>Injects malicious code into queries or web pages</td><td>Web forms, URLs</td></tr><tr><td>🦠 Malware</td><td>Ransomware, Worms, Trojans, Logic Bombs</td><td>Malicious software for encryption, spreading, or timed attacks</td><td>Email, USB, downloads</td></tr><tr><td>🕵️ Stealth</td><td>Spyware, Adware, Rootkits, Backdoors</td><td>Hidden monitoring, ad tracking, or persistent access</td><td>Software installs, OS exploits</td></tr><tr><td>🌐 Network</td><td>MitM, Session Hijacking, Replay, DNS Spoofing</td><td>Intercept or manipulate network communications</td><td>ARP spoofing, public Wi-Fi</td></tr><tr><td>💣 DoS/DDoS</td><td>SYN Flood, UDP Flood, DDoS via botnet</td><td>Overwhelm system resources to deny service</td><td>Single source or botnets</td></tr></table><h5>Protocol-Specific Attacks</h5><table class="info-table"><tr><th>Protocol</th><th>Attack</th><th>Description</th></tr><tr><td><strong>DHCP</strong></td><td>DHCP Spoofing, Starvation, Rogue DNS</td><td>Rogue server gives malicious config; exhaust IP pool; redirect DNS</td></tr><tr><td><strong>DNS</strong></td><td>Cache Poisoning, Hijacking, Tunneling, Amplification</td><td>False records, redirect DNS, data exfiltration, DDoS amplification</td></tr><tr><td><strong>ARP</strong></td><td>ARP Spoofing, Flooding, Gratuitous ARP Abuse</td><td>Fake ARP replies for MitM; exhaust switch CAM table; wrong MAC-IP mapping</td></tr></table><h5>TCP SYN Flood — Explained</h5><p>Normal: SYN → SYN-ACK → ACK (3-way handshake). <strong>SYN Flood:</strong> Attacker sends many SYN with fake IPs, never completes handshake. Server fills half-open connection queue → legitimate users can't connect. <strong>DDoS variant:</strong> Multiple bots send SYNs simultaneously. Defense: SYN cookies, rate limiting, stateful firewalls.</p>` },
        { title:'📐 TCP Communication Flow', body:`<h5>3-Way TCP Handshake (Connection Setup)</h5><p><strong>SYN →</strong> Client sends SYN (synchronize) packet to server<br><strong>← SYN-ACK</strong> Server responds with SYN-ACK (synchronize-acknowledge)<br><strong>ACK →</strong> Client sends ACK (acknowledge) — connection established!</p><h5>4-Way TCP Termination</h5><p><strong>FIN →</strong> Initiator sends FIN (finish)<br><strong>← ACK</strong> Receiver acknowledges<br><strong>← FIN</strong> Receiver sends their own FIN<br><strong>ACK →</strong> Initiator acknowledges — connection closed.</p><h5>TCP Flags (Control Bits)</h5><ul><li><strong>URG</strong> — Urgent data</li><li><strong>ACK</strong> — Acknowledgment</li><li><strong>PSH</strong> — Push data immediately</li><li><strong>RST</strong> — Reset connection</li><li><strong>SYN</strong> — Synchronize (start connection)</li><li><strong>FIN</strong> — Finish (end connection)</li></ul><h5>Packet Structure</h5><p>Every packet has a <strong>Header</strong> (source/dest IP, ports, flags, sequence numbers) and a <strong>Payload</strong> (actual data being transmitted).</p>` }
    ],
    caseStudies: [],
    flashcards: [
        { front:'OSI Model — 7 Layers', back:'Physical → Data Link → Network → Transport → Session → Presentation → Application. Mnemonic: "Please Do Not Throw Sausage Pizza Away"' },
        { front:'TCP/IP Model — 4 Layers', back:'Network Access → Internet → Transport → Application. The practical model used on the Internet.' },
        { front:'TCP 3-Way Handshake', back:'SYN → SYN-ACK → ACK. Establishes a reliable connection. SYN flood exploits this by never completing the handshake.' },
        { front:'4-Way TCP Termination', back:'FIN → ACK → FIN → ACK. Gracefully closes a TCP connection from both sides.' },
        { front:'DHCP DORA Process', back:'Discover → Offer → Request → Acknowledge. How devices automatically get IP addresses.' },
        { front:'ARP Function', back:'Address Resolution Protocol maps IP addresses to MAC addresses on a local network via broadcast request.' },
        { front:'ARP Spoofing', back:'Attacker sends fake ARP replies to associate their MAC with another IP, enabling Man-in-the-Middle attacks.' },
        { front:'Port 443 vs 80', back:'443 = HTTPS (TLS encrypted). 80 = HTTP (unencrypted). Always use HTTPS.' },
        { front:'Port 22', back:'SSH — Secure Shell for encrypted remote login (also used by SFTP).' },
        { front:'Port 502', back:'Modbus TCP — Industrial control protocol with NO built-in security.' },
        { front:'Port 3389', back:'RDP — Remote Desktop Protocol. Often targeted in brute-force attacks.' },
        { front:'Well-Known vs Ephemeral Ports', back:'Well-known (0-1023): assigned by IANA for common services. Ephemeral (49152-65535): temporary client-side ports.' },
        { front:'Hub vs Switch vs Router', back:'Hub = dumb broadcast (L1). Switch = smart MAC-based forwarding (L2). Router = routes between networks using IP (L3).' },
        { front:'IDS vs IPS', back:'IDS = Detect & Alert (out-of-path). IPS = Detect & Block (inline). IPS adds slight latency but actively prevents attacks.' },
        { front:'DMZ Purpose', back:'Demilitarized Zone = buffer between Internet and internal LAN. Hosts public-facing servers while isolating internal resources.' },
        { front:'NAT (Network Address Translation)', back:'Translates private IPs to a single public IP. Types: Static, Dynamic, PAT. Conserves IPv4 addresses and hides internal structure.' },
        { front:'VLAN Purpose', back:'Virtual LAN = logical network grouping for segmentation. Devices in same VLAN communicate as if on same physical network. Improves security, performance, management.' },
        { front:'Subnetting Purpose', back:'Divides large networks into smaller, isolated segments. Benefits: isolates segments, reduces broadcast traffic, enhances security. CIDR notation: /24 = 254 usable hosts.' },
        { front:'MAC Address Format', back:'48-bit hardware identifier (e.g., 00:1A:2B:3C:4D:5E). First 3 bytes = manufacturer (OUI), last 3 bytes = device-specific. Used at Layer 2.' },
        { front:'IPv4 Private IP Ranges', back:'Class A: 10.0.0.0-10.255.255.255, Class B: 172.16.0.0-172.31.255.255, Class C: 192.168.0.0-192.168.255.255. Not routable on Internet.' },
        { front:'DNS Spoofing / Cache Poisoning', back:'Attacker inserts false DNS records into a resolver\'s cache, redirecting users to malicious sites without their knowledge.' },
        { front:'DHCP Starvation Attack', back:'Attacker floods DHCP server with many requests using spoofed MACs, exhausting the IP pool so legitimate users can\'t get addresses.' },
        { front:'Wireshark', back:'Graphical packet analyzer. Captures/inspects network packets in real-time. Useful for troubleshooting, protocol analysis, and security investigation.' },
        { front:'Star vs Mesh Topology', back:'Star: all devices connect to central switch (scalable, easy management). Mesh: every device connects to every other (max redundancy, expensive).' },
        { front:'TCP vs UDP', back:'TCP: connection-oriented, reliable, ordered (web, email). UDP: connectionless, fast, no guarantee (streaming, DNS, gaming).' }
    ]
},
session3: {
    hero: { title:'Session 3: Enterprise Network Security', desc:'Master enterprise IT security challenges, OWASP Top 10, security misconfigurations, cloud security threats & best practices, Defence in Depth, and Zero Trust Architecture.' },
    concepts: [
        { title:'🏢 Enterprise Network Security Challenges', body:`<p>Enterprise IT networks face evolving threats that require layered defenses:</p><table class="info-table"><tr><th>#</th><th>Challenge</th><th>Threat</th><th>Example</th><th>Consequence</th></tr><tr><td>1</td><td>Insider Threats</td><td>Malicious or negligent employees</td><td>Employee downloads sensitive data to USB</td><td>Data breach, IP theft</td></tr><tr><td>2</td><td>Phishing & Social Engineering</td><td>Emails/calls tricking users</td><td>Fake CEO email requesting wire transfer</td><td>Financial fraud, credential theft</td></tr><tr><td>3</td><td>Unpatched Systems & Outdated Protocols</td><td>Old software with known vulnerabilities</td><td>Legacy Windows server running SMBv1 exploited via WannaCry</td><td>Remote code execution, network compromise</td></tr><tr><td>4</td><td>Misconfigured Firewalls & Access Controls</td><td>Incorrect rules or excessive permissions</td><td>Database server open to internet with default credentials</td><td>Unauthorized access, data breach</td></tr></table>` },
        { title:'🔟 OWASP Top 10 (2023) — Complete', body:`<p>The OWASP Top 10 is the standard awareness document for web application security. Mnemonic: <em>"Big Clever Hackers Infiltrate Systems Via Identity, Software Logs & Servers."</em></p><table class="info-table"><tr><th>#</th><th>Risk</th><th>Description</th><th>Example</th><th>Mitigation</th></tr><tr><td>A1</td><td>Broken Access Control</td><td>Users act outside intended permissions</td><td>Changing URL /account/123 → /account/456 to see others' data</td><td>RBAC, validate IDs, server-side authorization</td></tr><tr><td>A2</td><td>Cryptographic Failures</td><td>Weak/missing encryption exposing sensitive data</td><td>Storing passwords in plain text, using MD5</td><td>TLS (HTTPS), bcrypt/argon2 hashing, encrypt at rest</td></tr><tr><td>A3</td><td>Injection Attacks</td><td>SQL, NoSQL, OS command, LDAP injection</td><td>SQL: ' OR '1'='1 bypasses login</td><td>Parameterized queries, input sanitization, ORM</td></tr><tr><td>A4</td><td>Insecure Design</td><td>Security flaws at design stage</td><td>Unlimited login attempts → brute force</td><td>Threat modeling, rate limiting, secure design patterns</td></tr><tr><td>A5</td><td>Security Misconfiguration</td><td>Improper security settings</td><td>Default admin/admin credentials, directory listing</td><td>Change defaults, disable unused features, regular patching</td></tr><tr><td>A6</td><td>Vulnerable & Outdated Components</td><td>Using outdated frameworks/libraries</td><td>Outdated Struts2 → Equifax breach</td><td>npm audit, OWASP Dependency-Check, keep updated</td></tr><tr><td>A7</td><td>ID & Auth Failures</td><td>Weak authentication, session flaws</td><td>Weak password allowed (password123), no MFA</td><td>Strong password rules, MFA, secure sessions</td></tr><tr><td>A8</td><td>Software & Data Integrity Failures</td><td>Insecure updates, CI/CD pipelines</td><td>App updates from untrusted source</td><td>Code signatures, checksums, safe deserialization</td></tr><tr><td>A9</td><td>Logging & Monitoring Failures</td><td>Insufficient logging/alerting</td><td>No logs for failed logins → unnoticed brute force</td><td>Centralized logging (SIEM), alerts, protect logs</td></tr><tr><td>A10</td><td>SSRF (Server-Side Request Forgery)</td><td>Server tricked into making internal requests</td><td>User input makes server request http://localhost:8080/admin</td><td>Whitelist domains, block internal requests, segment networks</td></tr></table>` },
        { title:'🔧 Security Misconfigurations — 5 Critical Types', body:`<table class="info-table"><tr><th>Misconfiguration</th><th>Meaning</th><th>Risk</th><th>Fix</th></tr><tr><td><strong>1. Open Ports</strong></td><td>Ports left open unnecessarily</td><td>Attackers scan and exploit them</td><td>Close unused ports, regular port scanning</td></tr><tr><td><strong>2. Default Credentials</strong></td><td>Factory-set usernames/passwords unchanged</td><td>Easy unauthorized access</td><td>Change all defaults immediately, enforce strong passwords</td></tr><tr><td><strong>3. Unrestricted Admin Access</strong></td><td>Admin panel accessible to everyone</td><td>Full system compromise</td><td>Restrict admin access by IP, require MFA</td></tr><tr><td><strong>4. Lack of Segmentation</strong></td><td>No separation between networks</td><td>Attacker moves freely once inside</td><td>VLANs, firewalls, DMZ between zones</td></tr><tr><td><strong>5. Weak Firewall Rules</strong></td><td>Misconfigured, allowing broad access</td><td>Unauthorized traffic passes through</td><td>Regular rule audits, least-privilege access</td></tr></table><p><strong>Combined Exploitation Path:</strong> An attacker scans for open ports → finds default credentials → gains admin access → moves freely due to no segmentation → escalates through weak firewall rules → full compromise.</p>` },
        { title:'☁️ Cloud Security Challenges', body:`<table class="info-table"><tr><th>Challenge</th><th>Meaning</th><th>Risk</th></tr><tr><td><strong>Shared Responsibility Confusion</strong></td><td>Both cloud provider and customer share security duties — misunderstanding creates gaps</td><td>Critical assets left unprotected</td></tr><tr><td><strong>Data Leakage / Misconfiguration</strong></td><td>Sensitive data exposed due to misconfigured storage or permissions</td><td>Public S3 buckets, exposed databases</td></tr><tr><td><strong>Insecure APIs</strong></td><td>Cloud APIs for integration are weak or unprotected</td><td>Direct attack surface for exploitation</td></tr><tr><td><strong>Weak IAM</strong></td><td>Improper Identity & Access Management policies</td><td>Privilege escalation, unauthorized access</td></tr><tr><td><strong>Cloud Vendor Lock-in</strong></td><td>Dependency on single provider makes migration difficult</td><td>Limited flexibility, increased risk</td></tr></table>` },
        { title:'🔒 Cloud Security Best Practices', body:`<table class="info-table"><tr><th>Practice</th><th>Description</th><th>Example</th></tr><tr><td><strong>1. Encrypt Data at Rest & In Transit</strong></td><td>At rest: AES-256 for stored data. In transit: TLS/SSL for moving data</td><td>Healthcare app encrypts patient records (rest) + HTTPS (transit)</td></tr><tr><td><strong>2. Use MFA</strong></td><td>Two or more factors: know (password) + have (OTP) + are (fingerprint)</td><td>Stolen password useless without phone OTP</td></tr><tr><td><strong>3. Audit Permissions Regularly</strong></td><td>Apply Principle of Least Privilege (PoLP) — users only get needed access</td><td>Intern should NOT have admin rights to production servers</td></tr><tr><td><strong>4. Use CSPM Tools</strong></td><td>Cloud Security Posture Management auto-checks for misconfigurations</td><td>CSPM detects publicly accessible AWS S3 bucket → alerts admin</td></tr><tr><td><strong>5. Enable SIEM</strong></td><td>Security Information & Event Management for real-time log analysis</td><td>SIEM flags multiple failed logins from unusual locations → brute-force alert</td></tr></table><p><strong>Together:</strong> Protecting data (encryption) + Securing access (MFA + audits) + Detecting risks (CSPM + SIEM) = layered cloud defense.</p>` },
        { title:'🛡️ Defence in Depth — Layered Security', body:`<table class="info-table"><tr><th>Layer</th><th>Protection Techniques</th><th>Purpose</th></tr><tr><td><strong>Perimeter</strong></td><td>Firewalls, IDS/IPS</td><td>Block external threats at the boundary</td></tr><tr><td><strong>Network</strong></td><td>VLANs, Network Access Control</td><td>Segment and control internal traffic</td></tr><tr><td><strong>Endpoint</strong></td><td>Antivirus, EDR</td><td>Protect individual devices</td></tr><tr><td><strong>Application</strong></td><td>Code reviews, WAF</td><td>Secure application logic</td></tr><tr><td><strong>Data</strong></td><td>Encryption, DLP</td><td>Protect sensitive information</td></tr><tr><td><strong>User</strong></td><td>Authentication, awareness training</td><td>Secure human access points</td></tr></table><h5>Real-Time Example: Online Banking</h5><ol><li>Firewall & IDS/IPS — Blocks suspicious traffic</li><li>WAF — Filters SQL injection attempts</li><li>Secure Authentication — Username + Password + 2FA/OTP</li><li>Encryption (TLS/SSL) — Secures login and transaction data in transit</li><li>Access Controls — Only authorized staff can access customer data</li><li>Monitoring & Logging — Track abnormal login attempts</li><li>Incident Response — Freeze account if fraud detected</li></ol><p><em>Even if one layer fails (hacker bypasses firewall), the others still protect.</em></p>` },
        { title:'🚫 Zero Trust Architecture', body:`<p><strong>"Never trust, always verify"</strong> — the modern security philosophy replacing traditional perimeter-based security.</p><table class="info-table"><tr><th>Principle</th><th>Description</th></tr><tr><td>Continuous Identity Validation</td><td>Validate user/device identity at every access request, not just at login</td></tr><tr><td>Micro-Segmentation</td><td>Divide network into tiny zones; each zone has its own access policy</td></tr><tr><td>Least Privilege</td><td>Users get minimum access needed — nothing more</td></tr><tr><td>Assume Breach</td><td>Design systems assuming attackers are already inside</td></tr></table><p><strong>Why Zero Trust for Manufacturing:</strong> Traditional perimeter security fails with cloud apps, remote work, IIoT in smart factories. Zero Trust protects every access point regardless of location.</p>` }
    ],
    caseStudies: [],
    flashcards: [
        { front:'OWASP Top 10 Mnemonic', back:'"Big Clever Hackers Infiltrate Systems Via Identity, Software Logs & Servers" = Broken Access, Crypto Failures, Injection, Insecure Design, Security Misconfig, Vulnerable Components, ID/Auth Failures, Software Integrity, Logging Failures, SSRF.' },
        { front:'A1: Broken Access Control', back:'Users act outside intended permissions. Example: changing URL to access another user\'s account. Fix: RBAC, server-side authorization, validate session IDs.' },
        { front:'A3: Injection Attacks', back:'Malicious code injected into queries. SQL Injection: \' OR \'1\'=\'1 bypasses login. Fix: parameterized queries, input sanitization, ORM frameworks.' },
        { front:'A5: Security Misconfiguration', back:'Default credentials, open ports, directory listing. Example: admin/admin on production server. Fix: change defaults, disable unused features, regular patching.' },
        { front:'A10: SSRF', back:'Server-Side Request Forgery — attacker tricks server into making requests to internal systems. Fix: whitelist domains, block internal requests, network segmentation.' },
        { front:'5 Security Misconfigurations', back:'1. Open Ports, 2. Default Credentials, 3. Unrestricted Admin Access, 4. Lack of Segmentation, 5. Weak Firewall Rules. Combined = full system compromise path.' },
        { front:'Cloud Shared Responsibility', back:'Provider secures: physical infra, network, hypervisor. Customer secures: OS, apps, data, access control. Confusion between these creates security gaps.' },
        { front:'IaaS vs PaaS vs SaaS Security', back:'IaaS: customer manages OS+apps+data. PaaS: customer manages apps+data. SaaS: customer manages only data & user access. More "as a service" = less customer responsibility.' },
        { front:'Defence in Depth', back:'Layered security: Perimeter (firewalls) → Network (VLANs) → Endpoint (antivirus) → Application (WAF) → Data (encryption) → User (MFA). If one layer fails, others protect.' },
        { front:'Zero Trust Core Principle', back:'"Never trust, always verify." Continuous identity validation, micro-segmentation, least privilege, assume breach. Replaces traditional perimeter-based security.' },
        { front:'CSPM Tools', back:'Cloud Security Posture Management — automatically checks cloud environments for misconfigurations, compliance issues, and vulnerabilities. Example: detecting public S3 buckets.' },
        { front:'SIEM', back:'Security Information and Event Management — collects and analyzes logs for suspicious activities in real-time. Example: flagging multiple failed logins from unusual locations.' },
        { front:'Principle of Least Privilege (PoLP)', back:'Users get only the minimum access needed to do their job. Regular audits detect and remove excess privileges. Interns should NOT have admin rights.' },
        { front:'Cloud Vendor Lock-in', back:'Dependency on a single cloud provider makes migration difficult and risky. Mitigate with multi-cloud strategy and open standards.' },
        { front:'MFA (Multi-Factor Authentication)', back:'Requires 2+ factors: something you KNOW (password) + something you HAVE (OTP/phone) + something you ARE (fingerprint). Prevents access even if password is stolen.' }
    ]
},
session4: {
    hero: { title:'Session 4: Industrial Networks & Criticality in OT', desc:'Deep dive into PLCs, SCADA, DCS, HMIs, Digital Twins, OT vs IT networks, the Purdue Model, ICS architecture, PLC attacks & vulnerabilities, critical system identification, and security controls.' },
    concepts: [
        { title:'🔧 PLC — Programmable Logic Controller', body:`<p>An <strong>industrial computer</strong> designed for controlling machinery in real-time. Rugged, reliable, and often embedded in critical operations.</p><ul><li>Executes <strong>ladder logic</strong> or <strong>structured text</strong> programming</li><li>Controls: motor control, conveyor belts, temperature regulation, robotic arms</li><li>Contains two RAM areas: <strong>main memory</strong> (executing program logic) and <strong>register memory</strong> (temporary storage)</li><li>Best for <strong>real-time industrial control</strong> applications</li></ul><h5>PLC Security Challenges</h5><table class="info-table"><tr><th>Challenge</th><th>Explanation</th><th>Example</th></tr><tr><td><strong>Designed for Availability, Not Security</strong></td><td>PLCs prioritize uptime over security</td><td>Power plant PLC keeps turbines running even under cyber threat</td></tr><tr><td><strong>Weak/Hardcoded Credentials</strong></td><td>Default admin/admin, sometimes hardcoded by vendor</td><td>Attacker finds default credentials in online manual</td></tr><tr><td><strong>No Encryption</strong></td><td>PLC-to-SCADA communication often in plain text</td><td>Attacker sniffs "STOP PUMP" command and alters to "START PUMP"</td></tr><tr><td><strong>Rarely Updated</strong></td><td>Firmware updates require production shutdown</td><td>Plant keeps outdated firmware for months — known vuln exploited</td></tr><tr><td><strong>Exposed via Remote Access/USB/Vendors</strong></td><td>Multiple entry points for malware</td><td>Infected vendor laptop or USB spreads malware to PLC network</td></tr></table>` },
        { title:'⚔️ PLC Attacks & Vulnerabilities', body:`<table class="info-table"><tr><th>Attack</th><th>Description</th><th>Mitigation</th></tr><tr><td><strong>Bypass Logic Attack</strong></td><td>Attacker manipulates register memory values dynamically, bypassing control logic without modifying the main program</td><td>Restrict write access to PLC memory, memory integrity checks, authentication for programming access, network segmentation</td></tr><tr><td><strong>Force Output Attack</strong></td><td>Exploits unauthenticated "force output" functionality to remotely change motor speeds, valves, switches — no authentication needed</td><td>RBAC for force output access, MFA, firewalls/VPNs, real-time logging of force commands</td></tr><tr><td><strong>Replay Attack</strong></td><td>Attacker captures legitimate PLC commands and replays them later to compromise the system</td><td>Encryption (TLS/VPN/IPsec), timestamping & sequence numbers, challenge-response authentication</td></tr><tr><td><strong>Man-in-the-Middle (MitM)</strong></td><td>Attacker intercepts communication between PLC and programming tools (e.g., Siemens Step 7 uses ISO-TSAP with NO encryption — all data sent as plaintext)</td><td>TLS/VPN/IPsec encryption, mutual authentication, digital signatures, IDS, network segmentation</td></tr><tr><td><strong>S7 Authentication Bypass</strong></td><td>Even password-protected Siemens PLCs can have authentication bypassed due to protocol weakness</td><td>Use newer PLCs with encrypted authentication, MFA, VLANs, IDS, regular firmware updates</td></tr></table>` },
        { title:'📡 SCADA — Supervisory Control & Data Acquisition', body:`<p>SCADA is an ICS used to <strong>monitor, control, and automate</strong> industrial processes across large, complex systems.</p><h5>What SCADA Does</h5><ul><li><strong>Supervises:</strong> Monitors data from sensors and machines</li><li><strong>Controls:</strong> Sends commands (open/close valves, start/stop motors)</li><li><strong>Acquires Data:</strong> Collects and logs real-time data from field devices</li><li><strong>Displays:</strong> Provides dashboards to human operators</li></ul><h5>SCADA Components</h5><table class="info-table"><tr><th>Component</th><th>Role</th></tr><tr><td><strong>RTUs</strong> (Remote Terminal Units)</td><td>Collect data from field devices and send to central systems</td></tr><tr><td><strong>PLCs</strong></td><td>Local controllers that automate responses</td></tr><tr><td><strong>SCADA Software</strong></td><td>Centralized software to monitor, control, visualize, store data</td></tr><tr><td><strong>HMI</strong></td><td>Dashboard/screens operators use to interact with the system</td></tr></table><p><strong>Used in:</strong> Power grids, oil & gas, water systems, manufacturing, transportation. SCADA = the "brain and eyes" of industrial systems.</p>` },
        { title:'🏗️ DCS — Distributed Control System', body:`<p>Used for <strong>continuous process control</strong> (chemical manufacturing, oil refining). Control elements are <strong>distributed across the plant</strong> rather than centralized.</p><table class="info-table"><tr><th>Feature</th><th>DCS</th><th>SCADA</th></tr><tr><td>Primary Use</td><td>Continuous, complex process control (within a plant)</td><td>Supervisory monitoring over wide geographic areas</td></tr><tr><td>Control Type</td><td>Closed-loop (automatic within plant)</td><td>Open-loop (operator intervention via supervisory commands)</td></tr><tr><td>Response Time</td><td>Fast, real-time, millisecond range</td><td>Slower, seconds to minutes</td></tr><tr><td>Scalability</td><td>Limited to a plant/facility</td><td>Highly scalable, covers large regions</td></tr><tr><td>Communication</td><td>High-speed internal plant networks</td><td>Wide-area networks (WAN, cellular, satellite)</td></tr><tr><td>Operators' Role</td><td>Minimal (automatic response)</td><td>Significant (supervisory decisions)</td></tr><tr><td>Examples</td><td>Refineries, power generation</td><td>Water distribution, electric grids, pipelines</td></tr></table><h5>DCS vs PLC</h5><table class="info-table"><tr><th>Feature</th><th>PLC</th><th>DCS</th></tr><tr><td>Logic Type</td><td>Discrete (Fast On/Off)</td><td>Analog (Continuous PID Loops)</td></tr><tr><td>Architecture</td><td>Scalable but siloed</td><td>Unified, whole-plant system</td></tr><tr><td>HMI</td><td>Separate add-on software</td><td>Built-in and deeply integrated</td></tr><tr><td>Cost</td><td>Cheaper for small/medium tasks</td><td>Expensive, lower long-term cost for giant plants</td></tr><tr><td>Best For</td><td>Packing machines, cranes, conveyors</td><td>Oil refineries, power plants, mines</td></tr></table>` },
        { title:'🪞 Digital Twins', body:`<p>A <strong>high-fidelity virtual replica</strong> of a physical asset that behaves exactly like the real thing because it's fed by the same data.</p><h5>How It Works: The "Shadow" Concept</h5><ul><li><strong>Physical side:</strong> Sensors on real machine send data (vibration, heat, flow)</li><li><strong>Virtual side:</strong> Twin receives data and calculates expected performance based on physics</li><li><strong>The Gap:</strong> If the real machine behaves differently than the Twin, the system detects anomalies before humans notice</li></ul><table class="info-table"><tr><th>Feature</th><th>Traditional Testing</th><th>Digital Twin Testing</th></tr><tr><td>Risk</td><td>High (testing on live equipment)</td><td>Zero (tested in a "sandbox")</td></tr><tr><td>Cost</td><td>Expensive (physical parts)</td><td>Lower (purely software-based)</td></tr><tr><td>Speed</td><td>Slow (one test at a time)</td><td>Fast (1,000 "what-if" scenarios at once)</td></tr><tr><td>Timeline</td><td>After construction</td><td>During design (Virtual Commissioning)</td></tr></table><p>Core of <strong>Industry 4.0 and 5.0</strong> — helps engineers avoid costly "oops" moments.</p>` },
        { title:'🏛️ Purdue Model (PERA) — ICS Network Architecture', body:`<p>A hierarchical framework (developed 1990s by Purdue University) used in ICS to organize networks into <strong>layers (0-4) + DMZ</strong>.</p><table class="info-table"><tr><th>Level</th><th>Name</th><th>Function</th><th>Examples</th></tr><tr><td>0</td><td>Physical Process</td><td>Actual equipment and physical processes</td><td>Sensors, actuators, motors, valves, conveyors</td></tr><tr><td>1</td><td>Basic Control</td><td>Controllers converting sensor data to commands</td><td>PLCs, drives, IEDs</td></tr><tr><td>2</td><td>Supervisory Control</td><td>Monitoring and visualization</td><td>SCADA, HMI</td></tr><tr><td>3</td><td>Manufacturing Operations</td><td>Plant optimization, production management</td><td>MES, historian, batch management</td></tr><tr><td>DMZ</td><td>Buffer Zone</td><td>Secure bridge between OT and IT</td><td>Firewalls, IPS, data diodes, jump servers</td></tr><tr><td>4/5</td><td>Enterprise</td><td>Business systems and internet access</td><td>ERP, logistics, cloud, email</td></tr></table><h5>Security Implications</h5><ul><li><strong>Segmentation reduces attack surface</strong> — if corporate laptop gets ransomware, it won't reach PLCs</li><li><strong>Firewalls & IDS at critical junctions</strong> — between IT-DMZ and DMZ-OT</li><li><strong>No direct internet for Level 0-2</strong> — updates through controlled patching process</li><li><strong>Data diodes:</strong> Hardware enforcing one-way data flow (OT→IT monitoring, but no commands back)</li><li><strong>Jump servers:</strong> Hardened DMZ server for controlled remote access with MFA</li><li><strong>Secure VPNs:</strong> Encrypted, restricted to specific users and maintenance windows</li></ul>` },
        { title:'🔍 Critical Systems Identification in OT', body:`<p>Critical systems = those whose failure or compromise leads to major safety incidents, production shutdowns, data breaches, or regulatory non-compliance.</p><table class="info-table"><tr><th>System Type</th><th>Function</th><th>Examples</th></tr><tr><td>Control Systems</td><td>Real-time process management</td><td>PLCs, RTUs, DCS</td></tr><tr><td>Supervisory Systems</td><td>Monitoring interfaces</td><td>SCADA, HMI</td></tr><tr><td>Communication Systems</td><td>Data transfer protocols</td><td>Modbus, OPC, DNP3</td></tr><tr><td>Safety Systems</td><td>Emergency protection</td><td>Emergency Shutdown Systems (ESD), alarms</td></tr><tr><td>Support Systems</td><td>Data and engineering</td><td>Historian, batch control, engineering workstations</td></tr></table><h5>Classification Criteria</h5><ul><li><strong>Impact on Safety</strong> — Will failure cause injury or hazard?</li><li><strong>Impact on Operations</strong> — Will it stop production?</li><li><strong>Cyber Exposure</strong> — Is it connected to external networks?</li><li><strong>Redundancy</strong> — Are backups available?</li><li><strong>Compliance Requirements</strong> — Subject to audits?</li></ul><h5>Security Controls for Critical Systems</h5><ul><li>Network segmentation (DMZ, VLANs)</li><li>Multi-Factor Authentication</li><li>Allowlisting software & firmware</li><li>Offline backups and redundant systems</li><li>Regular patching & vulnerability scans</li></ul>` },
        { title:'🏭 Big Five Automation Vendors & Universal Automation', body:`<table class="info-table"><tr><th>Company</th><th>Region</th><th>Strongest Sector</th><th>Core Software</th></tr><tr><td><strong>Siemens</strong></td><td>Europe</td><td>Discrete (Auto, Aerospace)</td><td>TIA Portal / Xcelerator — highly integrated, high-end</td></tr><tr><td><strong>Rockwell</strong></td><td>North America</td><td>Discrete (Packaging, F&B)</td><td>FactoryTalk / Studio 5000 — king of US manufacturing</td></tr><tr><td><strong>Emerson</strong></td><td>North America</td><td>Process (Oil&Gas, Power)</td><td>DeltaV / Ovation — specialized in high-stakes fluids</td></tr><tr><td><strong>ABB</strong></td><td>Europe/Asia</td><td>Robotics & Heavy Industry</td><td>800xA — mining, metals, marine, robot arms</td></tr><tr><td><strong>Honeywell</strong></td><td>Global</td><td>Refining & Chemical</td><td>Experion PKS — safety-critical, advanced control rooms</td></tr></table><h5>Universal Automation (IEC 61499)</h5><table class="info-table"><tr><th>Feature</th><th>Traditional (IEC 61131)</th><th>Universal (IEC 61499)</th></tr><tr><td>Hardware</td><td>Proprietary & Locked</td><td>Hardware-Agnostic</td></tr><tr><td>Software</td><td>Tied to the brand</td><td>Portable "Function Blocks"</td></tr><tr><td>Communication</td><td>Centralized (Master/Slave)</td><td>Distributed (Event-driven)</td></tr><tr><td>Update Cycle</td><td>Requires stopping the line</td><td>"Hot-swappable" updates</td></tr><tr><td>Analogy</td><td>1990s Blackberry (Closed)</td><td>Modern Smartphone (Open)</td></tr></table>` }
    ],
    caseStudies: [
        { name:'Stuxnet PLC Attack (2010)', detail:'Exploited Siemens PLCs via USB. Altered centrifuge operation in Iran while reporting normal values to HMI. Demonstrated how malware can alter industrial processes undetected.', impact:'Damaged equipment without alerting monitoring systems. ~1,000 centrifuges destroyed.', lesson:'Even air-gapped PLCs can be compromised. Need: PLC change monitoring, motor speed logging, anomaly detection.' },
        { name:'Oldsmar Water SCADA Attack (2021)', detail:'Attacker accessed SCADA HMI via TeamViewer (no MFA) and increased lye levels to dangerous amounts. Critical systems: SCADA software, chemical dosing PLC, HMI, and the remote access tool.', impact:'Near-poisoning of water supply. Caught by alert operator.', lesson:'Identify critical systems and apply strict controls: MFA, network segmentation, logging, physical security for HMI.' }
    ],
    flashcards: [
        { front:'PLC (Programmable Logic Controller)', back:'Industrial computer for real-time machinery control. Executes ladder logic. Has main memory (program) and register memory (temp data). Designed for availability, not security.' },
        { front:'PLC Security Challenges (5)', back:'1. Designed for availability > security, 2. Weak/hardcoded credentials, 3. No encryption (plaintext commands), 4. Rarely updated (downtime fear), 5. Exposed via remote access/USB/vendors.' },
        { front:'Force Output Attack', back:'Exploits PLC force output functionality (no authentication needed). Attacker remotely changes motor speeds, valves. Fix: RBAC, MFA, logging, firewalls.' },
        { front:'Bypass Logic Attack', back:'Manipulates PLC register memory values dynamically, bypassing control logic without modifying the main program. Fix: memory integrity checks, write access restrictions.' },
        { front:'SCADA', back:'Supervisory Control and Data Acquisition. Centralized system to monitor/control remote equipment. Components: RTUs, PLCs, SCADA software, HMI. Used in power, oil, water.' },
        { front:'DCS vs SCADA', back:'DCS = localized, continuous, automatic control within one plant (refineries). SCADA = supervisory, large-scale monitoring over wide areas (pipelines, grids). DCS is faster but less scalable.' },
        { front:'DCS vs PLC', back:'PLC = discrete (on/off), scalable, cheaper, separate HMI. DCS = analog (continuous PID), unified whole-plant system, built-in HMI, better for large process plants.' },
        { front:'Digital Twin', back:'Virtual replica of physical asset fed by real sensor data. Detects anomalies when real behavior diverges from model. Zero-risk testing, 1000x faster "what-if" scenarios.' },
        { front:'Purdue Model Levels', back:'L0: Physical Process → L1: Basic Control (PLCs) → L2: Supervisory (SCADA/HMI) → L3: Manufacturing Operations (MES) → DMZ → L4/5: Enterprise (ERP/cloud). DMZ prevents OT/IT compromise.' },
        { front:'Data Diode', back:'Hardware device enforcing ONE-WAY data flow. Plant data sent out for monitoring, but NO commands can be injected back. Critical for OT-to-IT data sharing.' },
        { front:'Jump Server', back:'Hardened server in DMZ where remote users connect first (with MFA), then get controlled access to OT systems. Vendors must use jump server, not direct SCADA access.' },
        { front:'Critical vs Non-Critical OT Systems', back:'Critical: safety hazards if compromised (PLCs, DCS, ESD, fire alarms). Non-critical: minor disruption (HVAC, lighting, CCTV). Critical systems need strictest controls and lowest downtime tolerance.' },
        { front:'Criticality Classification Criteria', back:'5 factors: 1. Safety impact, 2. Operations impact, 3. Cyber exposure, 4. Redundancy availability, 5. Compliance requirements.' },
        { front:'IEC 61499 vs IEC 61131', back:'61131 = traditional proprietary, locked hardware, master/slave. 61499 = universal, hardware-agnostic, portable function blocks, event-driven, hot-swappable. Like Blackberry vs Smartphone.' },
        { front:'ISO-TSAP Protocol Vulnerability', back:'Used by Siemens Step 7 to program PLCs. NO encryption — all data sent as plaintext. Enables replay attacks and MitM. Fix: TLS/VPN/IPsec, mutual authentication.' }
    ]
},
session5: {
    hero: { title:'Session 5: Industrial Protocols', desc:'Master Modbus, DNP3, Profibus, Ethernet/IP, OPC (DA/UA), and ICCP — their functions, vulnerabilities, real-world attack scenarios, and security mitigations.' },
    concepts: [
        { title:'📋 What Are Industrial Protocols?', body:`<p>Communication rules between devices in OT/ICS. Used for PLCs, SCADA, RTUs, sensors, actuators. Enable <strong>real-time data exchange</strong> in manufacturing.</p><table class="info-table"><tr><th>Protocol</th><th>Primary Use</th><th>Key Feature</th><th>Key Weakness</th></tr><tr><td><strong>Modbus</strong></td><td>General process control — simple polling</td><td>Simple, universal, widely used since 1979</td><td>NO authentication, NO encryption, NO checksum (TCP)</td></tr><tr><td><strong>DNP3</strong></td><td>Electric utilities, water systems</td><td>Reliable, timestamp support, event-driven</td><td>Legacy DNP3 lacks encryption (fixed in Secure DNP3/DNP3-SA)</td></tr><tr><td><strong>Profibus</strong></td><td>High-speed factory automation</td><td>Fast, deterministic, real-time</td><td>Proprietary, no built-in security</td></tr><tr><td><strong>Ethernet/IP</strong></td><td>Industrial Ethernet standard</td><td>Uses TCP/IP + CIP protocol</td><td>Open ports, susceptible to scanning & DoS</td></tr><tr><td><strong>OPC (DA/HDA)</strong></td><td>Middleware between devices and software</td><td>Interconnects control systems with Windows</td><td>Legacy versions unencrypted, relies on DCOM</td></tr><tr><td><strong>OPC UA</strong></td><td>Modern secure middleware</td><td>TLS encryption, digital certificates</td><td>Misconfigured security policies, weak certificate management</td></tr><tr><td><strong>ICCP</strong></td><td>Power grid inter-control center communication</td><td>SCADA data exchange between utilities</td><td>Misconfiguration can expose grid data</td></tr></table>` },
        { title:'🔌 Modbus Protocol — Deep Dive', body:`<p>Developed by Modicon (1979). <strong>Master-Slave</strong> protocol, widely used for PLCs and SCADA. Application layer (OSI Layer 7). Uses request/response methodology with three PDUs: Request, Response, Exception.</p><h5>Modbus Security Concerns</h5><table class="info-table"><tr><th>Concern</th><th>Description</th><th>Mitigation</th></tr><tr><td>No Authentication</td><td>Only needs valid address + function code — easily guessed/spammed</td><td>Firewalls with DPI: only allow Modbus from authorized Master IP</td></tr><tr><td>No Encryption</td><td>Commands sent as clear text — easily captured and spoofed</td><td>VPN tunnel between Master and Slave devices</td></tr><tr><td>No Checksum (TCP)</td><td>Checksum at transport layer, not application — easier to craft malicious commands</td><td>IDS/IPS that understands Modbus protocol</td></tr><tr><td>No Broadcast Suppression (Serial)</td><td>All serial devices receive all messages — enables DoS</td><td>Secure gateways, network segmentation</td></tr><tr><td>Programmability</td><td>Designed to program controllers — attacker can reprogram PLCs</td><td>Strict access controls on programming commands</td></tr></table><h5>Real-World Threats: Water Tank Monitoring</h5><ul><li><strong>False Data Injection:</strong> Fake sensor readings (50% when actually overflowing at 95%)</li><li><strong>Unauthorized Command Injection:</strong> Sending "Turn Pump ON" repeatedly to burn out motor</li><li><strong>DoS:</strong> Flooding slave device, preventing legitimate monitoring</li></ul>` },
        { title:'⚡ DNP3 — Distributed Network Protocol', body:`<p>Designed for <strong>electric utilities</strong>. Master-Outstation communication. Reliable in noisy environments. Supports <strong>time-stamped data</strong>.</p><h5>DNP3 Threats & Mitigations</h5><table class="info-table"><tr><th>Threat</th><th>Scenario</th><th>Mitigation</th></tr><tr><td>Spoofing / False Command</td><td>Fake "Open Breaker" command causes targeted blackout</td><td>Secure DNP3 (DNP3-SA) authentication</td></tr><tr><td>MitM Attack</td><td>Change "Breaker Tripped" alert to "Breaker OK" — hiding real fault</td><td>Secure DNP3 encryption</td></tr><tr><td>Replay Attack</td><td>Record valid "Close Breaker" command, resend during maintenance</td><td>DNP3-SA anti-replay mechanisms</td></tr><tr><td>DoS</td><td>Flood IED during storm, prevent critical trip alerts</td><td>Network segmentation, firewalls, IDS</td></tr><tr><td>Eavesdropping</td><td>Passively listen to unencrypted traffic to map system</td><td>Secure DNP3 encryption, physical security</td></tr></table><p><strong>Key Point:</strong> Legacy DNP3 has all these vulnerabilities. <strong>DNP3-SA (Secure Authentication)</strong> was designed to fix them with encryption and authentication.</p>` },
        { title:'🏭 Profibus Protocol', body:`<p>Developed in Europe (Siemens, 1980s). High-speed industrial automation. Two types:</p><table class="info-table"><tr><th>Feature</th><th>Profibus PA (Process Automation)</th><th>Profibus DP (Decentralized Peripherals)</th></tr><tr><td>Primary Use</td><td>Monitoring in hazardous/explosive areas</td><td>High-speed factory/machine automation</td></tr><tr><td>Environment</td><td>Hazardous (Zone 0, 1, 2)</td><td>General factory floor</td></tr><tr><td>Key Technology</td><td>Intrinsic Safety, MBP Physical Layer</td><td>Standard RS-485</td></tr><tr><td>Power Source</td><td>Bus-powered (power + data same wires)</td><td>Devices powered separately</td></tr><tr><td>Max Speed</td><td>31.25 kbit/s (fixed)</td><td>Up to 12 Mbit/s</td></tr></table><h5>Profibus Threats</h5><ul><li><strong>Unauthorized Command Injection:</strong> No authentication — any device on network can send commands</li><li><strong>MitM:</strong> Unencrypted traffic can be intercepted and altered</li><li><strong>DoS:</strong> Junk messages disrupt time-critical communication loop</li><li><strong>Reconnaissance:</strong> All commands/sensor readings visible to eavesdroppers</li></ul><p><strong>Primary Mitigation:</strong> Network segmentation + physical security (it was designed for isolated networks, not connected environments).</p>` },
        { title:'🌐 Ethernet/IP & OPC Protocols', body:`<h5>Ethernet/IP (EIP)</h5><p>Industrial Ethernet standard using TCP/IP + UDP/IP with CIP (Common Industrial Protocol). Threats include unauthorized access, packet sniffing, command injection/replay, DoS, and device configuration tampering.</p><p><strong>Key Defense:</strong> CIP Security™ — adds TLS/DTLS encryption and device authentication to Ethernet/IP.</p><h5>OPC (OLE for Process Control)</h5><p>Middleware between devices and software apps. Three main variants:</p><table class="info-table"><tr><th>Variant</th><th>Status</th><th>Security</th></tr><tr><td><strong>OPC DA</strong> (Data Access)</td><td>Legacy</td><td>Unencrypted, relies on DCOM (often misconfigured)</td></tr><tr><td><strong>OPC HDA</strong> (Historical Data)</td><td>Legacy</td><td>Same vulnerabilities as DA</td></tr><tr><td><strong>OPC UA</strong> (Unified Architecture)</td><td>Modern</td><td>Built-in TLS encryption, digital certificates, platform-independent</td></tr></table><p><strong>OPC UA Risks:</strong> Misconfigured security policy (choosing "None"), weak certificate management, implementation vulnerabilities (buffer overflows). <strong>Fix:</strong> Always use SignAndEncrypt policy, implement PKI, use OPC Foundation-certified products.</p>` },
        { title:'🔗 ICCP — Inter-Control Center Protocol', body:`<p>Also known as TASE.2 or IEC60870-6. Used for <strong>communication between control centers</strong> in the energy industry. Client/server model over TCP/IP.</p><h5>ICCP Functions</h5><ul><li>Establishing connections between control centers</li><li>Reading/transmitting information (energy market data, emails)</li><li>Notifications of alarms and exceptions</li><li>Configuration and control of remote devices</li></ul><h5>ICCP Threats & Mitigations</h5><table class="info-table"><tr><th>Threat</th><th>Description</th><th>Mitigation</th></tr><tr><td>Unauthorized Access</td><td>Attacker connects to ICCP server, sends unauthorized commands</td><td>RBAC, whitelist peer IPs, network segmentation</td></tr><tr><td>Eavesdropping</td><td>Intercept traffic between control centers to steal grid data</td><td>VPN encryption, dedicated fiber optic lines</td></tr><tr><td>MitM</td><td>Alter power flow values (500MW → 50MW) or block alarms</td><td>VPN with digital certificates, IDS/IPS</td></tr><tr><td>DoS</td><td>Flood ICCP server — operators go "blind" to neighboring region</td><td>Rate limiting, redundant communication paths</td></tr><tr><td>Misconfiguration</td><td>Firewall/router mistake exposes ICCP server</td><td>Strict change management, regular security audits</td></tr></table>` },
        { title:'🔐 Industrial Protocol Security Comparison', body:`<table class="info-table"><tr><th>Security Concern</th><th>Modbus</th><th>Profibus</th><th>DNP3</th></tr><tr><td>Clear-text communication</td><td>✅ Yes — all unencrypted</td><td>✅ Yes — all unencrypted</td><td>Legacy: Yes / Secure DNP3: No (encryption)</td></tr><tr><td>Lack of authentication</td><td>✅ Yes — obeys any device</td><td>✅ Yes — no master verification</td><td>Legacy: Yes / Secure DNP3: No (authentication)</td></tr><tr><td>Replay & injection vulnerable</td><td>✅ Yes — easily captured/replayed</td><td>✅ Yes — disrupts timed automation</td><td>Legacy: Yes / Secure DNP3: No (anti-replay)</td></tr><tr><td>False command exploitation</td><td>✅ Yes — can control equipment</td><td>✅ Yes — can damage equipment</td><td>Legacy: Yes / Secure DNP3: No</td></tr></table><h5>Universal Mitigations</h5><ul><li>Network segmentation (separate OT & IT)</li><li>VPN/TLS gateways for protocol wrapping</li><li>Intrusion detection for protocol anomalies</li><li>Regular patching and vendor security updates</li></ul><p><strong>Why are insecure protocols still used?</strong> Massive installed base, replacement cost, proven reliability, designed for isolated networks (pre-internet era), and lack of secure alternatives for some use cases.</p>` }
    ],
    caseStudies: [],
    flashcards: [
        { front:'Modbus Protocol', back:'Developed 1979 by Modicon. Master-Slave, Layer 7. NO authentication, NO encryption, NO checksum (TCP). Widely used for PLCs/SCADA. Port 502.' },
        { front:'Modbus Security Threats (5)', back:'1. No authentication (guess address+function code), 2. No encryption (plaintext), 3. No checksum at app layer (TCP), 4. No broadcast suppression (serial DoS), 5. Programmability (can reprogram PLCs).' },
        { front:'DNP3 Protocol', back:'Distributed Network Protocol. For electric utilities. Master-Outstation. Reliable in noisy environments. Time-stamped data. Legacy lacks security; DNP3-SA fixes this.' },
        { front:'DNP3-SA (Secure Authentication)', back:'Modern secure version of DNP3. Adds encryption, authentication, and anti-replay mechanisms. Fixes all legacy DNP3 vulnerabilities.' },
        { front:'Profibus PA vs DP', back:'PA = Process Automation (hazardous areas, bus-powered, 31.25 kbit/s, MBP layer). DP = Decentralized Peripherals (factory floor, separate power, up to 12 Mbit/s, RS-485).' },
        { front:'OPC DA vs OPC UA', back:'OPC DA = legacy, Windows-only, DCOM-based, unencrypted. OPC UA = modern, platform-independent, built-in TLS encryption + digital certificates. Always prefer OPC UA.' },
        { front:'CIP Security™', back:'Security extension for Ethernet/IP. Provides TLS/DTLS encryption and device authentication. Addresses EIP\'s open-port and sniffing vulnerabilities.' },
        { front:'ICCP Protocol', back:'Inter-Control Center Protocol (TASE.2/IEC60870-6). Communication between energy control centers. Client/server over TCP/IP. Risks: unauthorized access, eavesdropping, MitM if misconfigured.' },
        { front:'Why Insecure Protocols Still Used', back:'Massive installed base, replacement cost, proven reliability, designed for isolated networks (pre-internet), lack of secure alternatives. Mitigation: wrap in VPN/TLS, segment, monitor.' },
        { front:'Protocol Wrapping', back:'Encapsulating insecure industrial protocol traffic inside a secure VPN or TLS tunnel. Adds encryption and authentication without replacing the protocol itself.' },
        { front:'Modbus Water Tank Attack Scenarios', back:'1. False data injection (fake readings), 2. Unauthorized command injection (burn out motor), 3. DoS (flood slave, lose visibility). All possible because NO built-in security.' },
        { front:'OPC UA Security Risks', back:'1. Misconfigured security policy (using "None"), 2. Weak certificate management, 3. Implementation vulnerabilities (buffer overflow). Fix: SignAndEncrypt policy, PKI, certified products.' }
    ]
},
session6: {
    hero: { title:'Session 6: Cloud Security & SASE', desc:'Understand cloud architecture (IaaS/PaaS/SaaS), cloud security threats by layer, shared responsibility model, best practices, and SASE (Secure Access Service Edge) for manufacturing.' },
    concepts: [
        { title:'☁️ Cloud Architecture Overview', body:`<h5>Cloud Service Models</h5><table class="info-table"><tr><th>Model</th><th>Description</th><th>Example</th><th>Customer Controls</th></tr><tr><td><strong>IaaS</strong></td><td>Virtualized infrastructure — users manage OS, apps</td><td>AWS EC2, Azure VMs</td><td>OS, applications, data</td></tr><tr><td><strong>PaaS</strong></td><td>Platform + runtime — users deploy apps</td><td>Google App Engine, Azure App Service</td><td>Applications, data</td></tr><tr><td><strong>SaaS</strong></td><td>Ready-to-use applications over internet</td><td>Gmail, Salesforce, Microsoft 365</td><td>Data, user access</td></tr></table><h5>Cloud Deployment Models</h5><table class="info-table"><tr><th>Model</th><th>Description</th><th>Example</th></tr><tr><td>Public Cloud</td><td>Services offered to multiple users via internet</td><td>AWS, Azure, Google Cloud</td></tr><tr><td>Private Cloud</td><td>Used by one organization only</td><td>VMware, OpenStack</td></tr><tr><td>Hybrid Cloud</td><td>Mix of public + private</td><td>Azure Hybrid, AWS Outposts</td></tr><tr><td>Community Cloud</td><td>Shared among organizations with similar goals</td><td>Government/research networks</td></tr></table><h5>Key Characteristics</h5><ul><li><strong>Scalability:</strong> Auto-adjust resources based on demand</li><li><strong>Elasticity:</strong> Scale up/down instantly</li><li><strong>Availability:</strong> Redundant systems ensure uptime</li><li><strong>Cost Efficiency:</strong> Pay only for what you use</li><li><strong>Automation:</strong> Self-service provisioning</li></ul>` },
        { title:'🔓 Cloud Security Threats', body:`<h5>Threats by Layer</h5><table class="info-table"><tr><th>Layer</th><th>Focus</th><th>Key Threats</th></tr><tr><td><strong>Application</strong></td><td>User apps, APIs, SaaS</td><td>Insecure APIs, account hijacking, insider threats, malware injection, compliance violations</td></tr><tr><td><strong>Data</strong></td><td>Storage & processing</td><td>Data breaches, data loss, weak IAM, lack of visibility</td></tr><tr><td><strong>Infrastructure</strong></td><td>Physical & virtual hardware (IaaS)</td><td>Misconfiguration, DoS, shared technology flaws (hypervisor), insufficient monitoring</td></tr></table><h5>Complete Cloud Threat Table</h5><table class="info-table"><tr><th>Threat</th><th>Example</th><th>Mitigation</th></tr><tr><td>Data Breach</td><td>Unauthorized data access</td><td>Encryption, MFA</td></tr><tr><td>Data Loss</td><td>Accidental deletion/corruption</td><td>Backup & recovery plans</td></tr><tr><td>Account Hijacking</td><td>Stolen credentials</td><td>MFA, continuous monitoring</td></tr><tr><td>Insecure APIs</td><td>Exposed endpoints</td><td>Secure coding, input validation</td></tr><tr><td>Misconfiguration</td><td>Public S3 bucket</td><td>Regular audits, CSPM tools</td></tr><tr><td>DoS Attack</td><td>Overloaded application</td><td>DDoS protection services</td></tr><tr><td>Insider Threat</td><td>Malicious admin</td><td>RBAC, audit logging</td></tr><tr><td>Weak IAM</td><td>Excessive privileges</td><td>Principle of Least Privilege</td></tr><tr><td>Shared Tech Flaws</td><td>VM escape (hypervisor vuln)</td><td>Isolation, patching</td></tr><tr><td>Lack of Monitoring</td><td>Unnoticed breach</td><td>SIEM, centralized logging</td></tr><tr><td>Shadow IT</td><td>Unauthorized cloud usage by employees</td><td>CASB, policy enforcement</td></tr><tr><td>Malware Injection</td><td>Malicious code in app environments</td><td>Code scanning, sandboxing</td></tr></table>` },
        { title:'🤝 Shared Responsibility Model', body:`<p><strong>Security in the cloud is a shared duty</strong> — understand your role vs. the provider's role.</p><table class="info-table"><tr><th>Component</th><th>Provider ✅</th><th>Customer ✅</th></tr><tr><td>Physical Infrastructure</td><td>✅</td><td>❌</td></tr><tr><td>Network & Hypervisor</td><td>✅</td><td>❌</td></tr><tr><td>OS & Middleware</td><td>❌</td><td>✅</td></tr><tr><td>Applications & Data</td><td>❌</td><td>✅</td></tr></table><h5>Responsibility by Service Model</h5><table class="info-table"><tr><th>Service Model</th><th>Provider Manages</th><th>Customer Manages</th></tr><tr><td><strong>IaaS</strong></td><td>Infrastructure + Virtualization</td><td>OS, Apps, Data</td></tr><tr><td><strong>PaaS</strong></td><td>Infrastructure + Platform (OS, middleware)</td><td>Apps, Data</td></tr><tr><td><strong>SaaS</strong></td><td>Everything except data access</td><td>Data, User Access</td></tr></table><p><strong>Key Insight:</strong> As you move from IaaS → PaaS → SaaS, the provider takes on MORE responsibility, but the customer ALWAYS owns their data and access control.</p>` },
        { title:'🔒 Cloud Security Best Practices', body:`<table class="info-table"><tr><th>Practice</th><th>Description</th></tr><tr><td>Enable MFA</td><td>Multi-Factor Authentication on all accounts</td></tr><tr><td>Encrypt at Rest & In Transit</td><td>AES-256 for storage, TLS/SSL for data movement</td></tr><tr><td>Apply RBAC</td><td>Role-Based Access Control — least privilege</td></tr><tr><td>Vulnerability Scanning</td><td>Regular scanning and patching of cloud resources</td></tr><tr><td>SIEM Monitoring</td><td>Centralized log analysis for threat detection</td></tr><tr><td>CASBs</td><td>Cloud Access Security Brokers for policy enforcement and Shadow IT detection</td></tr></table>` },
        { title:'🌐 SASE — Secure Access Service Edge', body:`<p>A <strong>cloud-native architecture</strong> that delivers networking and security together. Combines SD-WAN with security services.</p><h5>SASE Components</h5><table class="info-table"><tr><th>Component</th><th>Function</th></tr><tr><td><strong>SD-WAN</strong></td><td>Software-defined wide area networking for optimized routing</td></tr><tr><td><strong>SWG</strong> (Secure Web Gateway)</td><td>Filters malicious web traffic</td></tr><tr><td><strong>CASB</strong></td><td>Cloud Access Security Broker — enforces cloud security policies</td></tr><tr><td><strong>ZTNA</strong> (Zero Trust Network Access)</td><td>Identity-based access, replaces traditional VPN</td></tr><tr><td><strong>FWaaS</strong> (Firewall as a Service)</td><td>Cloud-delivered firewall protection</td></tr></table><h5>SASE Architecture Benefits</h5><ul><li>Security policies applied at the <strong>edge</strong> (not just data centers)</li><li><strong>Reduced latency</strong> — closer to users</li><li><strong>Better user experience</strong> — optimized routing</li><li><strong>Centralized security control</strong> for distributed users and devices</li></ul><h5>Why SASE for Manufacturing?</h5><ul><li>Supports <strong>secure remote access</strong> to OT/IT systems</li><li>Works well with <strong>IIoT and edge devices</strong></li><li>Enables <strong>Zero Trust architecture</strong></li><li>Simplifies <strong>cloud migration and compliance</strong></li></ul><p><strong>Discussion:</strong> Traditional perimeter-based security is no longer sufficient because of cloud apps, remote work, and IIoT in smart factories. SASE moves security to where users and devices are.</p>` }
    ],
    caseStudies: [],
    flashcards: [
        { front:'IaaS vs PaaS vs SaaS', back:'IaaS = you manage OS/apps/data (AWS EC2). PaaS = you manage apps/data (Google App Engine). SaaS = you manage only data/access (Gmail, Salesforce). More "aaS" = less you manage.' },
        { front:'Cloud Deployment Models (4)', back:'Public (AWS/Azure/GCP — shared), Private (one org — VMware), Hybrid (mix public+private), Community (shared by similar orgs — government).' },
        { front:'Shared Responsibility Model', back:'Provider: physical infra, network, hypervisor. Customer: OS, apps, data, access control. Customer ALWAYS owns data & access regardless of service model.' },
        { front:'Shadow IT', back:'Unauthorized cloud service usage by employees without IT department approval. Creates unmonitored security gaps. Fix: CASB tools for discovery and policy enforcement.' },
        { front:'CASB', back:'Cloud Access Security Broker — sits between users and cloud services to enforce security policies, detect Shadow IT, and ensure compliance.' },
        { front:'SASE', back:'Secure Access Service Edge — cloud-native architecture combining SD-WAN + SWG + CASB + ZTNA + FWaaS. Delivers networking and security together at the edge.' },
        { front:'SASE Components (5)', back:'1. SD-WAN (optimized routing), 2. SWG (web filtering), 3. CASB (cloud policy), 4. ZTNA (identity-based access), 5. FWaaS (cloud firewall).' },
        { front:'Why SASE for Manufacturing?', back:'Secure remote OT/IT access, works with IIoT/edge devices, enables Zero Trust, simplifies cloud migration. Traditional perimeter security insufficient for modern distributed environments.' },
        { front:'VM Escape', back:'Attack where malware breaks out of a virtual machine to attack the hypervisor or other VMs. A shared technology vulnerability in multi-tenant cloud environments. Fix: isolation, patching.' },
        { front:'Cloud Security Layers', back:'Application layer (APIs, SaaS), Data layer (storage, databases), Infrastructure layer (IaaS, hardware). Each has distinct threats and security goals.' },
        { front:'ZTNA vs Traditional VPN', back:'ZTNA = identity-based, per-application access, continuous verification. VPN = network-level access, once authenticated you\'re "in". ZTNA is more granular and secure.' },
        { front:'Perimeter Security Limitations', back:'Traditional perimeter (firewall-based) fails with cloud apps, remote work, IIoT. SASE/Zero Trust moves security to where users and devices are, not just the data center.' }
    ]
}
};
